window.THE_PROFESSOR_DB = [{"topic":"Part 10 - कुंडली अध्ययन-केतु - विवाह संबंधी विश्लेषण","text":"आप सभी को बहुत-बहुत नमस्कार\r\nआपमें से कई लोगों के कमेंट्स आए हैं कई\r\nलोगों के मैसेज भी आए हैं और कॉल भी ए रहे\r\nहैं आप लोगों को वीडियो पसंद ए रहे हैं और\r\nअपने अप्रिशिएट भी किया है इसके लिए आप\r\nलोगों का बहुत-बहुत धन्यवाद आज जो हमने\r\nटॉपिक लिया है यह बेसिकली बहुत लेटेस्ट\r\nकेस है तो इसलिए ये एग्जांपल में लिया है\r\nऔर यह वीडियो केवल ऑनलाइन व्यूवर्स के लिए\r\nहम लोग रिकॉर्ड कर रहे हैं\r\nइस वीडियो में समझेंगे की कैसे प्रॉपर\r\nएनालिसिस करना है सारी संभावनाओं को कैसे\r\nदेखना है और बाद में कैसे मैच करके फाइनल\r\nएनालिसिस करना है इससे पहले एक चीज और है\r\nकई लोगों के प्रश्न ए रहे हैं की ग्रहों\r\nकी युति के संबंध में अगर एक घर में\r\nदो-तीन चार ग्रह हैं तो उसको कैसे\r\nइंटरप्रिटेशन किया जाए इस संबंध में 2 दिन\r\nके अंदर या तीन दिन के अंदर एक वीडियो ए\r\nजाएगा जहां आप लोग बहुत आसानी से यह समझ\r\nपाएंगे की चाहे एक घर में कितने भी ग्रह\r\nहो बहुत आसानी से उनका इंटरप्रिटेशन कैसे\r\nकरना है कैसे समझना है ग्रह कैसे कम\r\nकरेंगे और जहां तक कोशिश है\r\nवैदिक ज्योतिष की हर चीज हम आपको यूट्यूब\r\nपर अवेलेबल कर देंगे जहां तक है मार्च से\r\nलेकर अप्रैल तक सारी चीज अवेलेबल हो\r\nजाएंगी तो उसके बाद शायद कोई भी क्लास की\r\nजरूरत ना पड़े चलिए तो अभी स्टार्ट करते\r\nहैं जैसा की मैं पता है आज हम चैट\r\nएनालिसिस कर रहे हैं आलिया भट्ट का फिल्म\r\nअभिनेत्री है\r\nसामने है हमारे उनका लगने चार्ट और बर्थ\r\nका समय है 1993 सबसे पहली चीज जो हम करते\r\nहैं 7000\r\nजो है मून\r\nतो हम मोनोट कर लेते हैं\r\nफिर हम बात करते हैं सेकंड हाउस के लौट के\r\nजो है\r\nसैटर्न\r\nतो हम यहां पर सेट कर लेते हैं\r\nइसके बाद यह दोनों अपनी दशा अंतर्दशा में\r\nविवाद दे सकते हैं यहां तक तो बहुत कॉमन\r\nहै मून की स्थिति देखते हैं की चंद्रमा\r\nकहां पर है चंद्रमा आपको देखेगा कुंडली के\r\n11वें घर में यहां पर\r\nहाउस ऑफ जेन में बैठा है फुलफिलमेंट ऑफ\r\nधीरे के हाउस में बैठा है अच्छी बात है\r\nलेकिन राशि है आठ नंबर जहां मून हो जाता\r\nहै नीचे राशि में यानी की चंद्रमा जो\r\nविवाह का कारक है यानी की सेवन था उसका\r\nलॉर्ड है वो इस समय नीचे राशि में बैठा है\r\nदूसरी चीज राहु के साथ बैठा है तीसरी चीज\r\nपांचवे घर से केतु की एस्पेक्ट में है अब\r\nयह तो ग्रहण हो गया राहु केतु मिल के\r\nग्रहण लगा देंगे चंद्रमा पे क्या और कुछ\r\nभी है मलेफिक इफेक्ट आप देखेंगे दूसरे घर\r\nमें बैठा शनि\r\nअपनी 10th एक्सपेक्ट भी मून पर डालेगा तो\r\nयह तो मैन्युफैक्चर हो गई तो क्या जातक की\r\nशादी नहीं होगी या होगी तो बहुत परेशानी\r\nसे होगी बहुत विलंब से होगी क्या ऐसा कुछ\r\nहोगा क्योंकि शादी तो हो गई और अच्छे से\r\nहुई और देश कल पत्र की बात करें तो सही\r\nसमय पर बल्कि जल्दी ही हुई क्योंकि इस आगे\r\nमें फिल्म इंडस्ट्री में शादी हो जाना\r\nबहुत आम बात नहीं है\r\nयानी की\r\nचंद्रमा की राहु से युति होना केतु से\r\nएस्पेक्ट होना और शनि की दृष्टि से भी\r\nशादी पे कोई फर्क नहीं पड़ा अप में आगे हम\r\nबहुत अच्छे से समझेंगे की ये कम कैसे करते\r\nहैं\r\nएक बार इसे हटा देते हैं जी\r\nअब देखिए हमने यहां पर यह देख लिया की मून\r\nमैरिज दे सकता है\r\nसैटर्न मैरिज दे सकता है क्या कोई और ग्रह\r\nजो मैरिज दे सकता है कुंडली के नीचे आपको\r\nग्रहों की डिग्री लिखे मिलेगी या गौर से\r\nदेखिएगा आपको सैन मिलेगा आप समझ सकते हैं\r\nयहां पे सैन क्या होगा सैन होगा हमारा\r\nडीके यह तो सबको क्लियर है दी के हम पढ़\r\nचुके हैं धारा कारक क्या और कोई प्लैनेट\r\nहै तो आपको सेकंड हाउस में एक मरकरी बैठा\r\nऔर देखेगा क्योंकि हम देखते हैं की सेकंड\r\nहाउस में जो प्लैनेट बैठा है उसका भी रोल\r\nहो सकता है तो लग्न चार्ट से हमने चार\r\nग्रह निकल लिए नोट कर लिए की हान इनका\r\nइंपॉर्टेंस हो सकता है\r\nऔर अपनी मूल रिकॉर्ड राशि में बैठा है\r\nतो 3 से 4 चीज सनी को बाली बनाती है अब\r\nआगे देखते हैं\r\nएक दूसरा तरीका भी हमने सिखा है की हम एक\r\nकुंडली को लग्न से ही नहीं chandrase भी\r\nदेखते हैं तो अगर मैं चंद्र कुंडली की बात\r\nकरूं तो हम पहला घर उसे मानते हैं जहां\r\nचंद्रमा बैठा है तो आपको पता है चंद्रमा\r\n11वे घर में है इसका लग्नेश कौन इसका\r\nलग्नेश है मार्स तो एक तो चंद्र कुंडली का\r\nलग्नेश हो गया अब हमें देखना है चंद्रमा\r\nसे दूसरे घर में कौन सा प्लैनेट है नाइंथ\r\nनंबर राशि में कोई प्लान नहीं है कोई फर्क\r\nनहीं पादना क्या चंद्रमा से सातवें घर में\r\nकोई प्लैनेट है जी हान चंद्रमा से सातवें\r\nनंबर पर आपको मिलेगा केतु\r\nहमने पढ़ा है दूसरा और सातवें प्लैनेट की\r\nदशा अंतर्दशा शादी दे सकती है की तू लिख\r\nलिया पर क्या केवल यही तक सीमित रह के\r\nप्रिडिक्शन कर पाएंगे केतु के बारे में\r\nचेक करना पड़ेगा अभी और देखते हैं कैसे\r\nकरेंगे केतु पे एस्पेक्ट किसकी है अभी\r\nदिखा सेवंथ से तो मून की एस्पेक्ट है मून\r\nहै 7000 का लोड यानी की केतु कैसा व्यवहार\r\nकरेगा जिसके साथ होगा जिस राशि में होगा\r\nया जिसके रिस्पेक्ट होंगी तो मून की\r\nएस्पेक्ट है यानी की विवाह का लोड है वह\r\nबिजनेस की राशि में बैठा है की तू वीनस भी\r\nविवाद देता है और तीसरी बात जुपिटर को\r\nदेखिए जुपिटर की नाइन daspect के तू पर है\r\nऔर जुपिटर फीमेल कुंडली में विवाह का कारक\r\nकी तू भी अच्छा दमदार प्रबल दावेदार बनता\r\nहै लेकिन अकेले लग्न और चंद्र कुंडली से\r\nनिर्णय नहीं कर सकते यह भी हमें जानते हैं\r\nतो अब इस चार्ट के नमाज पर चलते हैं\r\nnomanch में देखते हैं की इन ग्रहों की\r\nस्थिति क्या है तो सबसे पहले नमन पर देखिए\r\nदूसरा घर सातवां घर आपको देता है विनाश\r\nदोनों घर का मलिक एक और ये अपनी दिशा में\r\nविवाह करने का पूरा दमखम रखता है फिर बात\r\nकरते हैं सैटर्न की क्योंकि हमने लंदन में\r\nभी सैटर्न देखा सर्टेन यहां पर सातवें घर\r\nमें बैठा है और अपनी उच्च राशि में है\r\nयानी दोनों जगह से हमको सैटिन मिलता है यह\r\nभी प्रबल दावेदार हो जाता है यहां तक हो\r\nगया\r\nअब हम बात करते हैं धारा कारक की धारा\r\nकारक बैठा है यहां पर\r\nना तो दूसरे घर से कोई संबंध दिखता है ना\r\nसातवें घर से कोई संबंध दिखता है क्योंकि\r\nधारा कारक को naumas में अगर कम करना है\r\nतो या तो दूसरे घर से संबंध बनाए या\r\nसातवें से बनाए तो अभी कहीं नहीं बनाया\r\nइसने चलिए ठीक है अब चंद्र कुंडली में\r\nहमने देखा की हमें केतु मिला क्या केतु का\r\nरोल nomanch मैं कहीं है देख लेते हैं\r\nकेतु धारा कारक के साथ बैठा है\r\nकुछ बातें हो गई दूसरा अब आप गौर से समझिए\r\nकी तू जो है वह धारा कारक के साथ है और\r\nधारा कारक यानी की सूर्य पांचवे घर का\r\nमलिक है पांचवा घर होता है लव अफेयर का\r\nठीक और लग्न चार्ट में घर में बैठा है\r\nपांचवा घर होता है लव अफेयर का तो केतु\r\nकहीं ना कहीं यह सिंबॉलिस्ट करता है की\r\nअगर केतु इंवॉल्व होगा तो लव मैरिज के\r\nचांसेस हैं और कन्फर्मेशन मिलेगा इसमें\r\nबिल्कुल मिलेगा\r\nचंद्रमा यहां बैठा है मून से\r\nपांचवा घर देखिए मुंह से पांचवा घर आएगा\r\nफिर यही जहां धारा कारक और केतु बैठे हैं\r\nऔर पांचवे घर होता है आपका लव अफेयर का\r\nयानी की लग्न चार्ट में केतु पांचवे घर\r\nमें बैठा है विनाश की राशि में\r\nकेतु धारा कारक के साथ है जो पांचवे घर का\r\nमलिक है चंद्रमा से देखेंगे तो नौ मांस\r\nमें पांचवे घर में बैठा है तो यानी की\r\nकेतु इंवॉल्व हुआ तो लव मैरिज कर के ही\r\nमानेगा ये कंफर्म होता है यहां से\r\nहै तो वीनस की दशा अपने आप में विवाद दे\r\nसकती है और केतु प्रबल दावेदार है क्योंकि\r\nधारा कारक के साथ भी बैठा है और सैटर्न\r\nमें दावेदार है तो यहां मैं दो-तीन ग्रह\r\nआपको मिल जाते हैं चूंकि ऑलरेडी मैरिज हो\r\nचुकी है तो हम प्रिडिक्शन नहीं करने वाले\r\nहम केवल एनालिसिस कर रहे हैं और उसका रीजन\r\nये है क्योंकि केतु को डिटैचमेंट बोला\r\nजाता है तो क्या वो चीज है हर जगह\r\nप्रैक्टिकल सही होती है और यही चीज होती\r\nहै युति के साथ जब आप युति के बारे में\r\nपढ़ते हैं और कोई रिटर्न रूल आप याद कर\r\nलेते हैं की गुरु और राहु एक साथ हुए तो\r\nऐसा होगा पर वो होता नहीं है और कन्फ्यूजन\r\nहोता है आपको केवल इसीलिए तो हम किसी\r\nरिटर्न रूल की बात करेंगे ही नहीं जब उठी\r\nपढ़ेंगे कुछ फिक्स रूल है वो आपको बाद में\r\nदे देंगे पर वो प्रैक्टिकल कैसे कम करेंगे\r\nकैसे नहीं करेंगे उनकी विवेचना करने से\r\nअच्छा है हम यह समझ ले की तीन ग्रह बैठे\r\nहैं तो वो कम कैसे करेंगे तो अगले वीडियो\r\nमें दो से तीन दिन में ए जाएगा तो वह\r\nएनालिसिस हम कर लेंगे चलिए अब क्या करेंगे\r\nहमने तरीके से लगने चैट देख लिया चंद्र\r\nकुंडली देख ली और नमन शॉट देख लिया अभी\r\nइनको साथ में रख लेते हैं\r\nहमारे सामने पहली दशा मरकरी की जब जाती का\r\n2 साल की हुई\r\nकोई कम नहीं आता दूसरी दशा केतु की जब\r\nजाती का 9 साल के हो गई कोई फर्क नहीं\r\nपड़ेगा इससे अब आती है वीनस की दशा जहां\r\nजपते का 9 साल से लेकर 29 साल तक की उम्र\r\nमें थी अब देखा जाए तो 22 24 25 26 27 ये\r\nएक विवाह की उम्र मणि जाती है हमारे यहां\r\nतो जी हान वीनस की दशा एक सही टाइम पर\r\nशुरू हो रही है उसके बाद आती है सूर्य की\r\nक्या सूर्य की दशा में शादी नहीं होगी\r\nबिल्कुल होगी धारा कारक है करवा सकता है\r\nउसका लोड है लेकिन हमें पहली दशा मिलती है\r\nविनाश की\r\nहै अब हम लग्न को और नवमांश को कंपैरिजन\r\nकरते हैं चीज समझते\r\nदूसरे और सातवें घर का मलिक है उसके दशा\r\nसही समय पर ए रही है वीनस दे सकता है शादी\r\nऔर दूसरा यह विवाह का कारक भी है तो लग्न\r\nचार्ट के हिसाब से भी अगर बिजनेस की दशा\r\nचलेगी तो भी विवाह हो सकता है दूसरी चीज\r\nवीनस लग्न चार्ट में कहां बैठा है वीनस\r\nतीसरे घर में अपनी उच्च राशि में बैठा है\r\nपहली चीज तो ये है दूसरी चीज विंस पर\r\nजुपिटर की एस्पेक्ट है\r\nजुपिटर विवाह का कारक है फीमेल कुंडली में\r\nतो यहां भी सपोर्ट करता है\r\nक्लियर है\r\nचलिए\r\nइसका मतलब वीनस से कहीं\r\nघर में है और बिजनेस की राशि में है तो जब\r\nवीनस की दशा चलेगी तो आपका पांचवा घर\r\nएक्टिवेट होगा क्योंकि उसकी राशि है\r\nपांचवा घर किसका है\r\nलव मैरिज का लव का उसमें बैठा कौन है केतु\r\nतो केतु की दशा आएगी जब अंतर्दशा तो एक तो\r\nऑलरेडी घर है एक्टिव उसमें बैठक प्लानिंग\r\nएक्टिव तो पुरी कोशिश करेगा लव मैरिज कर\r\nदेने की तो केतु यहां पर प्रबल दावेदार हो\r\nजाता है लेकिन यह लव मैरिज कराएगा इसका\r\nसंबंध लैब से मेरे से कहां है\r\nतू आपको धारा कारक के साथ बैठा मिल जाएगा\r\nतो यहां एक आपको कन्फर्मेशन मिलता है\r\nदूसरा\r\nमून से पांचवा घर है तो फिर यह लव मैरिज\r\nऔर आपको लव अफेयर दिखाता है तो यहां आपको\r\nऑप्शन मिलेगा उसके बाद सैतान अगर आप देखो\r\nसैटर्न की 10th रिस्पेक्ट\r\nनहीं करेगा उच्च राशि में बैठा है इस घर\r\nको पर अटैक करेगा इस घर के लिए कम करेगा\r\nतो यह भी उसको नुकसान नहीं पहुंचाएगी अब\r\nएक चीज जो हमने नहीं पढ़ी वो चीज वो आगे\r\nआने वाली वीडियो में हम आपको क्लियर कर\r\nदेंगे और गला एक टॉपिक है जो बहुत कम आता\r\nहै प्रिडिक्शन में यूजुअली बहुत कम लोग\r\nहैं जो उसके बारे में बात करते हैं केतु\r\nका प्रबलता कहां से आती है इस चार्ट में\r\nउसका रीजन है\r\nवहां से 11 घर है जहां सूर्य और शुक्र\r\nबैठे हैं सूर्य धारा कारक है दोनों\r\nउनके केतु को अर्गला देंगे तो यह अगला\r\nbenefikar गिला है क्योंकि दोनों ही गृह\r\nमैरिज से रिलेटेड है एक धारा कारक है एक\r\nविवाह कारक है तो इस तरह\r\nसे एग्जांपल दे रहा हूं की argalayen कैसे\r\nकम करती हैं कैसे आपके सिस्टम को मजबूत\r\nकरती है इंप्रूव करते हैं\r\nएक छोटा सा गोचर और देख लेते हैं उसे समय\r\nका ताकि चीज और क्लियर हो जाएंगे हमें\r\nदेखिए मैरिज होती है इस डायरेक्शन में\r\nवीनस में केतु केतु में मार्स विनय समझ\r\nमें आया मुझे केतु समझ में आया मार्च को\r\nसमझ में आया क्योंकि मार्च 12 चंद्र\r\nकुंडली से देखा तो मार्च लग्नेश हुआ नवाज़\r\nमें देखोगे तो मार्च लगने स्थान\r\nवीडियो या उससे लास्ट वाले में शायद\r\nएक्सप्लेन किया था की लग्न जो है लगने जो\r\nहै वह मैरिज को नेगेटिव नहीं करेगा अब\r\nदेखिए\r\nविनाश की बात करें\r\nमंगल के साथ\r\nअच्छी बनती है ऊपर से इन दोनों के ऊपर\r\nमंकी एस्पेक्ट है हालांकि दो सवा दो दिन\r\nरहता है कुंडली में तो बहुत ज्यादा उसका\r\nमैटर नहीं कर रहे जुपिटर अपने स्वराशि में\r\nबैठा हुआ है अब बात करें केतु केतु की\r\nयुति धारा कारक के साथ बनी हुई है और\r\nलग्नेश खुद में बैठा है और दसवीं एस्पेक्ट\r\nभी केतु पर डालेगा और लग्नेश खुद इंवॉल्व\r\nहोगा तो क्या अपना विवाह खुद रोकेगा नहीं\r\nरोकेगा तो इसका मतलब है की चाहे राहु हो\r\nकेतु हो सनी हो मंगल हो हर ग्रह आपको\r\nव्यवहार दे सकता है बात यह है की एनालिसिस\r\nहोने चाहिए परफेक्ट कांबिनेशन निकलना\r\nचाहिए और बहुत स्ट्रांग होना चाहिए केवल\r\nएक जगह से पर्पस निकलेगा तो मजा नहीं आएगा\r\nआपको एनालिसिस करके देखना है की कितना\r\nस्ट्रांग कांबिनेशन है\r\nइसको दिल्ली में जो अभी एनालिसिस नहीं कर\r\nरहे\r\nएक छोटी सी चीज और है इसमें जो हालांकि\r\nहमें टॉपिक कवर नहीं किया लेकिन बात कर\r\nलेते हैं 10000 का लोड है बस\r\nजाके बैठा है थोड़ा उसमें अपनी उच्च राशि\r\nमें वीनस कारक है 10000 प्रोफेशन का वीनस\r\nकारक है 8 का ड्रामा का यानी की मूवी में\r\nएक्टिंग बनता है वो भी उच्च की राशि में\r\nजाके बैठ जाता है किसके साथ बैठा है सैन\r\nके साथ सैन किसका कारक है नाम और फेन नाम\r\nऔर शोहरत का दोनों मिलती हैं बहुत क्लियर\r\nहै तो यह स्पष्ट देखता है हालांकि अभी\r\nइसको कुंडली में हम डिटेल पर नहीं जा रहे\r\nलेकिन एक छोटी सी चीज है चार्ट आपको बता\r\nदेता है की क्या हो रहा है\r\nआई होप यह क्लियर होगा अब मैरिज\r\nप्रिडिक्शन आप करना थोड़ा बहुत स्टार्ट कर\r\nसकते हैं समझ सकते हैं चीजों को कैसे कम\r\nकरती है और युवती के संबंध में किसी भी\r\nतरह की घबराहट कम नहीं आती कोई फर्क नहीं\r\nपड़ता तीन ग्रहों चार ग्रह हो वह कम कैसे\r\nकरते हैं जब ये समझ लेंगे तो बहुत अच्छे\r\nसे कैलकुलेट आप लोग कर पाएंगे तो अगले\r\nवीडियो में हम वो लेके आएंगे इसके अलावा\r\nकोई भी chessashian हो कुछ और भी हो तो आप\r\nशेयर कर सकते हैं मैसेज कर सकते हैं\r\nव्हाट्सएप नंबर है आप लोगों के पास या आप\r\nयहां पर भी कमेंट कर सकते हैं तो नेक्स्ट\r\nवीडियो में मिलते हैं\r\nAll\r\nFrom the series"},{"topic":"Part 11 (2)- अर्गला विचार - सीखिए सम्पूर्ण पराशरी ज्योतिष-A New Beginning of Astrology -","text":"तो इस चैट में वीनस कौन-कौन ढूंढ\r\nअच्छा है\r\nअभी करते हैं डिस्कस\r\nतो लास्ट में हम लोग यहां तक पहुंच गए\r\nप्लैनेट के ऊपर यह भाव के ऊपर और रुकती\r\nकहां से हैं 12 से 10 से और तीन से\r\nrespectiveli यानी दूसरे हाउस के अगला को\r\n12 हाउस रोक लेगा यहां तक चीज क्लियर हो\r\nगई थी\r\nएक मतभेद और है किसको लेकर है वह है राहु\r\nऔर केतु को लेकर की कुछ विद्वानों का ऐसा\r\nमानना है की राहु केतु से संबंधित अर्गला\r\nको रिवर्स ऑर्डर में मानना चाहिए क्योंकि\r\nयह हमेशा वक्री होते हैं\r\nलॉजिक या उनका मत कुछ हद तक सही है लेकिन\r\nकई जगह इसके मतभेद मिलेंगे तो अभी के समय\r\nमें हम साधारण रूप से राहु और केतु की\r\nअर्गला भी बिल्कुल अन्य ग्रहों की तरह मैन\r\nके चलेंगे\r\nक्योंकि उसके सामने प्रमाण दिखाई दे रहे\r\nहैं कुंडली में तो हम वो मैन के चल रहे\r\nहैं कुछ स्पेशल केसेस हैं जाम समझेगी किस\r\nकेस में हमें अर्गला को रिवर्स करके मानना\r\nचाहिए तो बहुत ज्यादा अभी उसे समय चीजों\r\nमें नहीं जा रहे अब अगला स्टेप यह है की\r\nथोड़ा सा और दीप स्टडी करने वाले हैं हम\r\nकी अर्गला को रोकने में कौन से प्लैनेट\r\nसक्षम हो पाएंगे देखिए एक राशि 30 डिग्री\r\nकी होती है सबको पता है और अगर हम उसे\r\nराशि को 4 हसन में डिवाइड कर दें उसे साइन\r\nको तो पहला पाठ होगा\r\n15 से 12:30 डिग्री और चौथा पाठ होगा\r\n22:30 से 30 डिग्री यानी की 7:30 डिग्री\r\nके चार हिस्से में हमने एक राशि को बनता\r\nजब हम अर्गला की बात कर रहे हैं और वो\r\nक्यों बनता है उसका रीजन ये है\r\nकी एक प्लैनेट आपको और गला देगा\r\nअब वो राशि के किसी भी हिस्से में हो सकता\r\nहै वो पहले पार्ट में हो सकता है वो दूसरे\r\nहिस्से में हो सकता है वो तीसरे हिस्से\r\nमें हो सकता है वो चौथे हिस्से में हो\r\nसकता है\r\nविपरीत और गला यानी की इस अर्गला को रोकने\r\nवाला प्लैनेट भी चाहे वो 4थ फोर्थ पार्टनर\r\nहो सकता है थर्ड में हो सकता है सेकंड में\r\nहो सकता है और फर्स्ट में हो सकता है\r\nलेकिन हमें याद ही रखना है की जिस प्लैनेट\r\nसे और गला आएगी जिस प्लैनेट से आपके पास\r\nऔर गला आएगी वह कौन से हिस्से में है अगर\r\nवह फर्स्ट पार्ट में है अगर वह जीरो से\r\n7:30 डिग्री के अंदर है तो उसको केवल वही\r\nप्लैनेट रोक पाएगा जो\r\nराशि के चौथे हिस्से में है इसका मतलब\r\nदूसरे घर से आपको मंगल की अर्गला आई और\r\nमंगल की डिग्री है 6\r\nतो 12 घर में बैठा शैतान इसको तब रोक\r\nपाएगा जब वह चौथे हिस्से में हो याने की\r\nउसकी डिग्री होगी 22.5 से लेकर 30° में\r\nऐसे ही कोई अर्गला देने वाला प्लैनेट अगर\r\nसेकंड पार्ट में है यानी की साधे सात से\r\n15 डिग्री के अंदर में है तो उसको कौन रोक\r\nपाएगा 12वीं घर में बैठा प्लान है जो\r\nतीसरे हिस्से में है यानी की जिसका 15 से\r\n22.5° होना चाहिए\r\nदो नियम कम करेंगे बाकी तीसरे और चौथे के\r\nलिए कोई नियम नहीं है इसका मतलब तीसरे और\r\nचौथे हिस्से में बैठा प्लैनेट अगर गला\r\nदेगा तो वह अर्गला नहीं रुकेगी केवल दो ही\r\nकेस में अर्गला न्यूली फाइट होती है अब\r\nयहां नीली फाइट का मतलब क्या है\r\nफर्स्ट पार्ट की अर्गला को पुरी तरह\r\nरोकने वाले प्लैनेट को फोर्थ पार्ट में\r\nहोना पड़ेगा सेकंड पार्ट में बैठे प्लैनेट\r\nकी अर्गला को रोकने के लिए\r\nप्लैनेट रोकने वाले को थर्ड पार्ट में\r\nहोना पड़ेगा थर्ड और फोर्थ पार्ट में अगर\r\nबैठा प्लैनेट और गला देगा तो इसको कोई\r\nनहीं रोक सकता तो\r\nअगला kahlayengi मतलब की यह पूरा प्रभाव\r\nदेंगी देंगी यहां यह अर्गला पुरी तरह से\r\nनहीं rukengi बहुत मिनर से फर्क यह\r\nप्लैनेट दल सकता है इनके ऊपर ठीक है तो ये\r\nऔर इंडेक्स है की पुरी तरह से जैसे कल के\r\nएग्जांपल में हमने देखा था उसको दिल्ली\r\nमें मैंने बोला था की मंगल अर्गला में कम\r\nनहीं करेगा तो वह चीज इसलिए नहीं कर रही\r\nथी क्योंकि वह पंच मैच नहीं हो रहे तो\r\nकैसे याद रखना है फर्स्ट पार्ट के अर्गला\r\nको फोर्थ रोकेगा सेकंड पार्ट के अगला को\r\nथर्ड पार्ट रोकेगा बस इसके अलावा नहीं\r\nrukengi\r\nअब एक एग्जांपल और देख लेते हैं समझने के\r\nलिए की क्या अर्गला हर चैट में कम करती\r\nहैं\r\nअब सबसे पहले तो यह की वीनस कौन-कौन ढूंढा\r\nइस चार्ट में पहले यह बताएं\r\nक्योंकि वह शायद शुरू में दिखा की बॉलीवुड\r\nसे रिलेटेड कोई कुंडली होने वाली है तो हम\r\nविनर ढूंढेंगे है ना बिल्कुल होता है क्या\r\nहै मैंने जैसे बताया की बहुत सीमित दायरा\r\nहो गया है अब जैसे इसी कुंडली में अगर मैं\r\nबोलूं की टेंट हाउस रिलेटेड प्रॉब्लम है\r\nतो आप देखोगे टेंट हाउस पर कहीं शनि की\r\nएस्पेक्ट तो नहीं है आपने देखा हान सामने\r\nही बैठा है अच्छा शनि डेड हो जाता है\r\nकी चाहे वह योगकारक है बेनिफिट है कम कर\r\nरहा है नहीं कर रहा है\r\nनहीं नहीं चलिए तो अब एक चार्ट है आपके\r\nपास अब कहने को अगर आपको वैसे तो विनर\r\nढूंढना क्यों है आपको कोई फर्क नहीं पड़ता\r\nकुंडली किसकी है आपको तो यह देखना है की\r\nयह चार्ट आपको क्या बता रहा है ऐसे तो\r\nनहीं मिल रहा होगा रिलेशन 10000 से तो मैं\r\nआपको ढूंढ के दे देता हूं भवत भागम भागम\r\nदेखोगे तो दशम हाउस से दशम है आपका ये\r\nहाउस और इस हाउस का लोड है बस लो मिल गया\r\nतो बोल दो की हान मिल गया वह वीनस यानी की\r\nव्यक्ति बॉलीवुड में आठ ड्रामा या इन\r\nचीजों में जाएगा बन जाता है कॉन्सेप्ट\r\nअच्छा सा पर ऐसे कम नहीं होता तो हम करते\r\nहैं जो हमने सामान्यतः सिखा है क्या टेंथ\r\nलार्ड कहां है किसके साथ है किस घर में है\r\nसामने देखेंगे फोर्थ हाउस में आपको सैटर्न\r\nबैठा मिलेगा यानी हाउस फोर्थ है\r\nऔर अगर आप देखोगे गौर से तो यह मून के साथ\r\nही बैठा है मून की राशि भी चौथी है और मून\r\nkaryakat हुई है चौथे घर का यानी की आपको\r\nयहां से मिलता है सैटर्न और 4th हाउस तो\r\nक्या मैं बोल सकता हूं की इस व्यक्ति को\r\nअपने कैरियर में 4000 से संबंधित कम कर\r\nलेना चाहिए\r\nक्योंकि खुद टेंट हाउस में बैठा है दूसरा\r\nफोर्थ हाउस\r\nमें अपनी राशि में बैठा है यानी की इस\r\nव्यक्ति का 4th हाउस तो बहुत स्ट्रांग है\r\nउसको मिलने वाली है तो 4th हाउस से\r\nसंबंधित कम करवा सकते हैं\r\nपर क्योंकि आगे 9 मार्च में भी चेक करना\r\nहोता है तो 95 देख लेते हैं क्या कंडीशन\r\nबनती है\r\nशनि कहां बैठा है सैटर्न कहां पे है जवाब\r\nदेखोगे फोर्थ हाउस में बैठा है यह तो कमली\r\nहो गया ऊपर से\r\nमूल त्रिकोण राशि में बैठा है और क्या\r\nचाहिए आपको सीधे बोल दो की भाई जातक को\r\n4000 से रिलेटेड कम करवा दो शनि प्रबल है\r\nबोलते कौन राशि में बैठ गया केंद्र में घर\r\nमिला तो अब ये क्रूर भी नहीं रहा ऊपर से\r\nदोनों जगह चीज मैच होती है बहुत सिंपल\r\nवह समझने के लिए हमें एग्जांपल ले रहे हैं\r\nतो आगे एक बार फिर से अर्गला चेक करते हैं\r\nअपने लग्न चार्ट पर चलकर\r\nरोल है 4th हाउस का रोल है क्या यही फिक्स\r\nपॉइंट है क्योंकि हम d10 पर भी नहीं जा\r\nरहे तो हम argalaon से चीज चेक करते हैं\r\nटेंट हाउस पर किस ईयर किला है दूसरे घर से\r\nअगला नहीं है\r\n4th हाउस\r\nचलिए 4th हाउस\r\nक्या करेगा कुछ नहीं करेगा केतु कहां बैठा\r\nहै किस घर में 7000 का है 7000 प्रोफेशन\r\nके संबंधित जोड़े तो 7000\r\nआपके इंटरेक्शन का 7000 पब्लिक का और 7000\r\nभी नहीं है\r\nहै तो सैटर्न के ऊपर दो तो यह\r\nकर गला फिर से देखते हैं सैटर्न के ऊपर 11\r\nए रही है\r\nसूर्य कारक है नाम फेम पावर अथॉरिटी का और\r\nइस चार्ट में सूर्य पांचवे घर का मलिक भी\r\nहै तो पूरा आधिपत्य बनता है सूर्य का नाम\r\nफेम पावर अथॉरिटी पे तीन अर्गला हमने चेक\r\nकर ली लेकिन उसमें से जो इस घर की अगला है\r\nदूसरे घर की उसको रोकेगा कौन बार-बार घर\r\nतो क्या रुकेगी देख लेते हैं नीचे डिग्री\r\nदी हुई है मंगल को आप देखोगे 17 डिग्री\r\nमें है 17 डिग्री मतलब राशि का तीसरा\r\nहिस्सा और कोई प्लैनेट अगर राशि के तीसरे\r\nहिस्से में बैठा है तो उससे आने वाली\r\nफाइट नहीं\r\nहै या तो यह फर्स्ट में होता है या सेकंड\r\nपार्ट में होता तो हम इनके डिग्री देखते\r\nपर जो की मंगल तीस पार्ट में है यानी की\r\nअकेला नहीं रुकेगी तो यानी\r\nबैठे हैं तो थोड़ा बहुत इफेक्टिव जरूर\r\nडालेंगे ये कंफर्म है पुरी तरह से न्यूली\r\nफाइंड नहीं करेंगे लेकिन असर और इफेक्ट\r\nडालेंगे डालेंगे\r\nतो अब हमें\r\nलगने चार से जब हम अर्गला देखते हैं तो\r\nहमें मिलता है एक राहु का रोल\r\nएक हमें मिलता है\r\nमार्स का रोल\r\nसूर्य कारक है सरकार का गवर्नमेंट का राहु\r\nकारक है पॉलिटिक्स का मार्च यहां पर\r\nलग्नेश है जो फिफ्थ हाउस में बैठा है नाम\r\nफेम पावर अथॉरिटी सूर्य अपने आप में कारक\r\nहै नाम पावर अथॉरिटी का तो यह चीज मुझे अब\r\nदेख कर लगता है की अगर विश्वास करूं तो यह\r\nकुंडली यह चार्ट पॉलिटिक्स या किसी पब्लिक\r\nफिगर का होना चाहिए\r\nलेकिन अब इस चीज को क्या नवज अप्लाई करता\r\nहै परमिशन देता है स्ट्रेंथ बताता है तो\r\nउसके लिए देखना पड़ेगा देख लेते हैं\r\nटेंट हाउस\r\nसूर्य\r\nबैठता है\r\nफुलफिलमेंट ऑफ डिजायर में यहां बैठा है\r\nयुद्ध किसके साथ है राहु के साथ और किसके\r\nसाथ है मंगल के साथ लग्न चार्ट में इन सब\r\nका अर्गला से संबंध था राहु के अलग-अलग\r\nटेंट हाउस पर थी सूर्य की अरदाला टेंट\r\nहाउस के लॉट पर थी और क्या यह तीनों\r\nप्लैनेट अभी भी इसी कंडीशन में है बिल्कुल\r\nहै\r\nचलिए जाने की यह कन्फर्मेशन मुझे कहीं ना\r\nकहीं से मिलता है की यह कुंडली शनि या\r\nकेवल सत्तन के 4थ हाउस में होने से ना\r\nइफेक्ट देते हुए इसका इफेक्टिव कुंडली में\r\nज्यादा रहेगा क्योंकि आपको दो-दो\r\nकन्फर्मेशन मिलते हैं लेकिन हालांकि ये\r\nकन्फर्मेशन भी है की अगर जातक 4000\r\nरिलेटेड कम करेगा तो उसे बेनिफिट होगा ही\r\nहोगा ये कंफर्म है क्योंकि दोनों जगह बहुत\r\nबेहतरीन स्थिति मिलती है\r\nस्पष्ट ही चीज है की दोनों चीजों सामने\r\nएनालिसिस कर लिया\r\nऔर जहां आपको अब इसके बाद एक बार डिटेल और\r\nचेक कर लेंगे तो आपको और ज्यादा क्लेरिटी\r\nहो जाएगी की चीज कैसे कम करेंगे अभी\r\nफिलहाल हम इस चीज को प्रोफेशन वाले\r\nkauncept को बहुत ज्यादा डिटेल में नहीं\r\nदेख रहे हम ये देखना चाह रहे हैं की अर्ल\r\nकम करती हैं और अर्गला अगर लग्न चार्ट में\r\nबनती है तो क्या वो नमन शॉट में भी फलित\r\nहो रही है अगर हो रही है तो मानिए की बहुत\r\nस्ट्रांग रोल है उनका\r\nअब यह दोनों चैट हमारे सामने हैं\r\nअब इसमें चलिए बता देते हैं कुंडली है\r\nकिसकी यह कुंडली किसी बॉलीवुड की नहीं है\r\nयह कुंडली है मिस्टर लालू प्रसाद यादव की\r\nठीक है पॉलिटिक्स समझ में आता है कहां से\r\nआया नहीं तो आपके पहले कॉन्सेप्ट के हिसाब\r\nसे तो 4th हाउस का कम करना चाहिए था इस\r\nइंसान को लेकिन कहीं से कहीं\r\nरांची में कोई कमी नहीं है जमीन की\r\nसंपत्ति की व्हीकल की और ऊपर से शनि बैठ\r\nके इसको प्रोटेक्ट करेगी ही करेगा जहां\r\nसनी बैठेगा उसे घर को प्रोटेक्ट करेगा\r\nऔर यह जाता अगर इससे संबंधित कम भी करेगा\r\nतो भी सफलता मिलने निश्चित है बाकी चीज\r\nडिटेल में देखेंगे प्रोफेशन के जब देश में\r\nजाएंगे तब यहां में क्वेश्चन क्या है एक\r\nदशा है यह\r\nदिसंबर 2017 में दशा आती है मंगल मंगल के\r\nअंदर शनि शनि के अंदर शुक्र\r\nइस दशा में क्या होगा या क्या हुआ होगा यह\r\nसब को नॉर्मली पता है अगर डेट देखेंगे पर\r\nहम यह जानना चाहते हैं की इस दशा में\r\nप्रॉब्लम क्या हुई\r\nवीनस की महादशा में समझ लीजिए वीनस की\r\nमहादशा में ये मुख्यमंत्री बनते हैं दो\r\nबार ठीक है\r\n95 में बनते हैं या नहीं 29597 ऐसा कुछ\r\nकरके है 2 साल के लिए बनते हैं पर पंच साल\r\nके लिए बनते हैं तो 97 तक वीनस की महादशा\r\nइनको मुख्यमंत्री बना देती है ठीक है तो\r\nयहां तो वीनस की प्रत्यंतर से ए रही है अब\r\nअगर मैं देखूं\r\nतो आप कैसे देखेंगे दशा कम कैसे करेगी\r\nमंगल की दशा आएगी तो मंगल क्या-क्या चीज\r\nएक्टिवेट करेगा को दिल्ली में वो देख लेते\r\nहैं लग्न चार्ट में मंगल एक्टिवेट करेगा\r\nफर्स्ट हाउस क्योंकि उसी का घर है मंगल\r\nएक्टिवेट करेगा 8000 क्योंकि उसी की राशि\r\nहै और मंगल जहां बैठा है यानी की 5th हाउस\r\nयह तीन चीज मंगल एक्टिवेट करेगा इसी को\r\nक्रॉस चेक करेंगे नवांश में की नवांश में\r\nक्या-क्या एक्टिवेट होने वाला है\r\nरोमांच में एक्टिवेट होगा लग्न क्योंकि\r\nयहां भी लग्नेश है\r\nएक्टिवेट होगा सिक्स हाउस क्योंकि मंगल की\r\nराशि है और नमन एक्टिवेट होगा 11th हाउस\r\nक्योंकि मंगल यहां पर बैठा हुआ है अभी तक\r\nइन चारों के कांबिनेशन में केवल एक चीज\r\nकॉमन है जो है लग्नेश यानी लंदन वाला घर\r\nएक्टिवेट हो रहा है कॉमन\r\nसिमटेम के हिसाब से\r\nआगे बढ़ते हैं सैटर्न क्या करेगा\r\nबिल्कुल ठीक\r\nकरेगा और\r\nएस्पेक्ट कहां पर है\r\nहै तो एस्पेक्ट यहां पर तो इस हाउस को\r\nएक्टिवेट करेगा"},{"topic":"Part 11-अर्गला विचार- सीखिए सम्पूर्ण पराशरी ज्योतिष- A New Beginning of Astrology -","text":"गुड मॉर्निंग आज बात करेंगे और गला की\r\nयानी की इंटरवेंशन लेकिन उससे पहले एक\r\nमहत्वपूर्ण चीज है जो समझना जरूरी है\r\nज्योतिष शास्त्र में हमें कई सारे टूल्स\r\nदिए गए हैं प्रिडिक्शन के लिए लेकिन आजकल\r\nअब अंतर देखेंगे की हम लोग कुछ विशेष\r\nटूल्स का उसे करना ज्यादा बटर समझते हैं\r\nजैसे हाउसेस हो गया प्लैनेट के बारे में\r\nपढ़ लिया एस्पेक्ट देख ली ग्रुप यानी की\r\nहमने ग्रहों की yutiyan देख ली कुछ\r\nबेसिक्स ऊंच-नीच के देख लिए या कुछ स्पेशल\r\nयोग देख लिए\r\nलेकिन क्या यह simitta प्रिडिक्शन के लिए\r\nसही है या केवल इससे प्रिडिक्शन हो जाएगा\r\nक्योंकि हमारे पास उपग्रह है हमारे पास\r\nडिविजनल चार्ट्स हैं हमारे पास अर्थ लग्न\r\nहै घाटी लग्न है होरा लग्न है श्रीलंका है\r\nहमारे पास ashvarg है हमारे पास कई तरह की\r\nदशाएं हैं जब हमें किसी भी कल का सर्विस\r\nकरना है तो एक टूल किट होती है उसे धूल कट\r\nके हर टूल का अपना एक कम होता है और वह\r\nसारे टूल एक कांबिनेशन के बाद उसे करके आप\r\nप्रॉपर रिजल्ट ले पाते हो उसी तरह से यह\r\nसारे टूल्स हर एक जगह कहीं ना कहीं कोई ना\r\nकोई तो यूजफुल होता है अब अगर मैं आपको\r\nबोलूं की केवल अष्ट वर्ग का उसे कर लो बस\r\nदेख लो कौन सा ग्रह कहां बेनिफिट है और\r\nरिजल्ट डिक्लेयर कर दो क्या केवल अष्ट\r\nवर्ग से कुंडली का प्रिडिक्शन हो जाएगा\r\nअगर हो जाता तो बाकी टूल्स या इतना सब\r\nपढ़ने की जरूरत नहीं होती तो याद रखिएगा\r\nहर टूल को पढ़ना जरूरी है समझना जरूरी है\r\nकैसे उसे करना है किस जगह पर उसे करना है\r\nवो समझना बहुत जरूरी है और ऐसे ही टूल का\r\nनाम है जो उसका बाथरूम आज करने वाले हैं\r\nवो है अर्गला बहुत ही इंपॉर्टेंट टॉपिक है\r\nऔर आज के समय में इसकी इंपॉर्टेंस थोड़ी\r\nसी कम हो गई है क्योंकि लोग प्राय बहुत\r\nज्यादा उपयोग नहीं करते आप लोग जब समझेंगे\r\nकैसे कम करती है तो आपको लगने लगेगा की यह\r\nभी एक इंपॉर्टेंट टूल है जो बहुत हेल्प\r\nकरेगा आपको चीजों को एनालिसिस करने में\r\nदेखते हैं और गला होती क्या है आती कहां\r\nसे है\r\nतो और गला का बेसिक मतलब है कोई\r\nजब किसी दूसरे घर या दूसरे ग्रह के रिजल्ट\r\nमें परिणाम में हस्तक्षेप करें इंटरव्यू\r\nकरें उसका मतलब होता है अर्गला यानी की इफ\r\nआ इफ अन प्लैनेट इसे इनफ्लुएंसिंग डी\r\nअफेयर्स ऑफ आदर हाउस और प्लैनेट इसका मतलब\r\nयह अर्गला है तो फिर अर्गला एस्पेक्ट से\r\nअलग क्यों हो गई क्योंकि जब कोई प्लैनेट\r\nएस्पेक्ट डालता है दृष्टि डालता है तो\r\nउसका भी यही कम होता है वो कहीं ना कहीं\r\nइन्फ्लुएंस करता है किसी भाव के परिणाम को\r\nया तो बढ़ा देता है या कम कर देता है तो\r\nइसको एक ग्रीस में समझ लेते हैं पहला जो\r\nहमारा इन्फ्लुएंस होता है वह होता है राशि\r\nएस्पेक्ट राशि दृष्टि अभी आपका हुआ नहीं\r\nहोगा शायद\r\nइसका इन्फ्लुएंस बहुत कम होता है और बहुत\r\nछोटा सा टॉपिक है तो आगे कवर कर लेंगे कभी\r\nभी तो एक होता है राशि एस्पेक्ट इसका\r\nस्मॉल इन्फ्लुएंस होता है उसके बाद हमारे\r\nपास आता है प्लैनेट का एस्पेक्ट जो हम\r\nअच्छे से पढ़ चुके हैं बहुत कंक्रीट\r\nइन्फ्लुएंस है ये इन्फ्लुएंस की वजह से\r\nकिसी भी घर के परिणाम कम हो सकते हैं\r\nज्यादा हो सकते हैं यहां तक भी कोई इशू\r\nनहीं है अब आता है अर्जेला\r\nअर्गला किसी भी घर के रिजल्ट के कुछ\r\nफैक्टर में डिसाइडिंग फैक्टर का कम करती\r\nहै इसका मतलब यह है की अगर अर्गला ए रही\r\nहै तो वह उसे घर से संबंधित कुछ चीजों में\r\nइंटरफेयर भी करेगी और डिसीजन मेकिंग\r\nफैक्टर का कम भी करेगी क्योंकि हमने हर घर\r\nको अलग से पड़ा है मैन लीजिए किसी घर से\r\nआपको 20 चीज मिल रही है\r\nहर हाउस में 20 से 25 देख सकते हैं तो एक\r\nहाउस से 20 चीज मिल रही हैं तो क्या\r\nअर्गला पूरे की पुरी 20 चीजों पर असर\r\nडालेगी ऐसा नहीं होगा और गला कुछ चीजों पे\r\nकुछ सिलेक्टेड चीजों पे असर डालेगी और\r\nउनके बारे में डिसीजन लेने की कैपेसिटी या\r\nबहुत हद तक इन्फ्लुएंस करने का पावर और\r\nगला के पास होता है तो इसका मतलब अगर मैं\r\nबोलूं की जितना प्लैनेट की एस्पेक्ट जरूरी\r\nहै उतना ही अर्गला भी इंपॉर्टेंट हो जाती\r\nहै देख लेते हैं यह अर्गला जो है आपकी\r\nकहां से है\r\nबात करते हैं की आप फर्स्ट हाउस की बात कर\r\nरहे हो या फर्स्ट हाउस में बैठे प्लैनेट\r\nकी बात हम कर रहे हैं तो इसके लिए अगला\r\nकहां से आएगी देखिए अगर फर्स्ट हाउस की\r\nबात करूं तो यहां इंसान ने जन्म लिया जन्म\r\nलेने के बाद उसके जीवित रहने के लिए सबसे\r\nजरूरी चीज क्या है खाना पानी मिलना चाहिए\r\nनहीं तो जिंदा नहीं रहेगा खाना खान-पान का\r\nघर कौन सा सेकंड हाउस यानी की एक अगला\r\nआपकी आएगी सेकंड हाउस से यहां से और यह\r\nअर्जेला होती है सस्ती लांस की यानी की\r\nमें इनग्रेडिएंट का कम करती है इसलिए\r\nसेकंड हाउस की अर्गला को हम दूसरे नाम से\r\nजानते हैं जो की कहलाती इनग्रेडिएंट बेसिक\r\nइनग्रेडिएंट जो किसी भी घर का दूसरा घर\r\nआपको और गला देगा वह बहुत महत्वपूर्ण हो\r\nजाती है क्योंकि यह निश्चित करती है की\r\nउसे घर के परिणाम मिलेंगे नहीं मिलेंगे\r\nआपके पास अब कहां से आएगी फर्स्ट हाउस की\r\nबात करें तो हम आएंगे सस्ता\r\nग्रोथ का 4000 आपका मेंटल स्टेट का पीस ऑफ\r\nमाइंड\r\nदिखाता है और 4000\r\nदेगा तो वो एक ड्राइविंग फोर्स का कम\r\nकरेगा यानी की उसको बढ़ाने का कम करेगा\r\nजिस रिजल्ट की आप बात कर रहे हैं तो\r\nफर्स्ट हाउस के रिजल्ट चाहिए और 4th हाउस\r\nमें कोई प्लैनेट है तो वो उसे रिजल्ट को\r\nबढ़ाने में ऐसा ड्राइवर कम करेगा अब एक और\r\nअगला आती है वो कहां से आएगी वो आएगी 11\r\nनंबर हाउस से जो है आपका हाउस ऑफ गेट 11\r\nघर से आने वाली अर्गला को हम कहते हैं\r\nकैटालिस्ट का मतलब होता है\r\nआपको या आपके लिए एक प्रेरक यानी की\r\nप्रभाव को बढ़ाने वाला ग्रह की तरह कम\r\nकरेगा तो अगर मुझे फर्स्ट था उसके रिजल्ट\r\nचाहिए और यहां कोई प्लैनेट है तो वो आज\r\nउत्प्रेरक यानी की इसको तीव्र बनाने का या\r\nपरिणाम देने के लिए रिस्पांसिबल होने का\r\nकम कर देता है तो समझ सकते हैं की ये लगभग\r\nलगभग जैसे एस्पेक्ट कम करती है उतना ही\r\nप्रभाव अर्गला का भी होता है तो दूसरे घर\r\nसे चौथे घर से और 11वे घर से अर्गला आएगी\r\nहम किसी भी घर की बात करें वहां से दूसरा\r\nचौथा और 11\r\nअगला कम कैसे करेगी जल्दी से समझ लेते हैं\r\nमैन लीजिए आप यहां\r\nहो गया\r\n1920 का मामला चल रहा है सामने वाली\r\nपार्टी से ठीक है\r\nआपके 2 3 दोस्त इधर से मित्र आपके हाथों\r\nमें दिखे आपको क्या होगा परिणाम उन\r\nमित्रों को देख के वो आपके पास आए नहीं है\r\nबस आज आते हुए दिख रहे हैं आपको क्या होगा\r\nपरिणाम आपका जो मैटर 1920 चल रहा था आप\r\nवहां खुद को बहुत कंफर्टेबल महसूस करने\r\nलगोगे क्यों क्योंकि अब मेरे तीन दोस्त ए\r\nरहे हैं वहां पर वही अगर उल्टा हो जाए की\r\nतीन जो मित्र हैं यह आपके मित्र एन होके\r\nयह शत्रु हो जाएं तो क्या होगा\r\nऔर एक पहले से ही था चार शत्रु मिलकर आपसे\r\nझगड़ा करेंगे तो रिजल्ट सबको पता है की\r\nआपके साथ क्या होगा इसका\r\nभी हो सकती है बेनिफिट भी हो सकती है यह\r\nशुभ अर्गला भी हो सकती है पाप अर्गला भी\r\nहो सकती है डिपेंडिंग अपॉन की कौन से\r\nप्लैनेट इसको बनाएंगे लेकिन इफेक्ट आएगा\r\nदूसरे चौथे 11वें घर से यहां तक क्लियर\r\nहोगा\r\nएक एग्जांपल है कुछ दिन पहले हमने कुंडली\r\nएनालिसिस की थी एक जाते कहा की जहां हमने\r\nएक 15 30 नवंबर के आसपास का कुछ\r\nप्रिडिक्शन मैरिज का किया था है ना अब मैं\r\nनवाज़ वगेरा देख लिए द तो यहां हम पहुंच\r\nगए द की मार्च धारा कारक था और चार जगह से\r\nकन्फर्मेशन मिल रहा था इसलिए हमने इसको\r\nसिलेक्ट किया मरकरी सेक्स 7 था उसका लॉट\r\nथा इसलिए हमने इसको सिलेक्ट किया और मैंने\r\nआपको बताया था की वीनस की यहां पर\r\nअंतर्दशा देखने के लिए केवल\r\nइस हाउस पर अगला कहां से ए रही है क्या\r\nदूसरे घर से कोई अगला है जी नहीं है\r\nबिल्कुल\r\nविवाह का कारक है दूसरा 4th हाउस पर 4th\r\nहाउस की अर्गला भी दे रहा है यहां तक हो\r\nगया अब बात करते हैं की जो विवाह के लिए\r\nप्लैनेट हमने चूज किए एक हमने दूसरा घर का\r\nमलिक मंगल चूज किया एक 7थ हाउस का मलिक\r\nहमने मरकरी चूस किया यानी की मरकरी और\r\nमार्स यह कहां बैठे कुंडली में यह आपको\r\nदेखेंगे 12वें घर में यहां पे बैठे हैं\r\nक्या इनके ऊपर किसी की आरजू है देख लेते\r\nहैं दूसरे हाउस की\r\nचौथा उसकी कोई अगला नहीं है घूम के आएंगे\r\nतो आपको देखेगी अगला 11वे हाउस की यहां\r\nफिर से आपको विनाश और बूंद देखते हैं यानी\r\nकी आप समझ सकते हैं की विनर्स यहां पर\r\nप्लैनेट को भी अर्गला दे रहा है हाउस को\r\nभी अर्गला दे रहा है अब मून क्यों नहीं\r\nलिया मून पे भी तो विवाह कर सकता है\r\nबिल्कुल कराएगा क्योंकि 9 मार्च जब हमने\r\nकिया था तो वहां हमें बिजनेस निकल के ए\r\nरहा था सेकंड और सेवंथ का लॉट था शायद है\r\nना जब आप गोचर में हमने देखा तो जुपिटर और\r\nवीनस की युति थी अब याद कीजिएगा\r\nजुपिटर के अभी रोल यहां क्या है 1 सेकंड\r\nइसको हम क्लीन कर देते हैं पहले\r\nजी देखिए\r\nतो हमने देखा था गोचर में की मंगल यानी की\r\nमार्स और मरकरी की युति यहां थी मंगल अपने\r\nस्वराशि में बैठा था और केंद्र में यहां\r\nपे आपके पास जुपिटर और वीनस की युति बन\r\nरही थी\r\nजुपिटर यहां पर 7थ को 11वीं और गला दे रहा\r\nहै वीनस फॉर तरला दे रहा है क्या टूल्स का\r\nउसे करके आपके प्रिडिक्शन स्ट्रांग हो गई\r\nया नहीं हुए आपको यह पक्का कंफर्म होता है\r\nकी जॉब प्रिडिक्शन कर रहे हैं उसको इतनी\r\nजगह से सपोर्ट मिल जाएगा इसीलिए जितने\r\nज्यादा टूल्स कम प्रयोग कर पाएंगे उतना\r\nबेनिफिशियल हमारा रिजल्ट रह पाएगा\r\nआगे एक और चीज आती है इसमें\r\nअगला आएंगे तो क्या कुछ ऐसा है जो इनको\r\nरोक पाएगा बिल्कुल होगा क्यों बेनिफिट तो\r\nसबको अच्छी लगती है लेकिन जब मैंने तो\r\nक्या करेंगे तो आपको पता है हम इस घर की\r\nबात कर रहे हैं यहां से अर्गल आएगी आपके\r\nपास सेकंड हाउस की इस अर्गला को रोकेगा\r\n₹12000 का बैकअप प्लान डेट यानी दूसरे घर\r\nकी अर्गला को रोकने वाला कम करेगा ₹10000\r\nका प्लैनेट\r\nतो अगर आपके पास 4th हाउस से कोई अगला ए\r\nरही है और दसवीं घर में कोई प्लानिंग बैठ\r\nगया तो वह अर्गला ऑब्जेक्टिव हो जाएगी रुक\r\nजाएगी फिर वो कम नहीं करेगी तीसरी और आपके\r\nपास आती है कुंडली के 11वे घर से\r\n11वीं घर की अर्गला को रोक लेगा तीसरे घर\r\nमें बैठा प्लैनेट\r\nकरगल है और इन घरों में अर्गला को रोकने\r\nवाले घरों में प्लैनेट ए जाए तो मैंने फिर\r\nरुक जाएंगे अगर यह बेनिफिट है तो बेनिफिट\r\nरुक जाएंगी कुछ संदर्भ में पहले हम यह समझ\r\nलेते हैं दूसरे चौथे ग्यारहवें घर के अगला\r\nको कौन-कौन रोकता है दूसरे की को रोकेगा\r\nबार-बार चौथे की को रोकेगा दसवां घर 11वें\r\nकी को रोकेगा तीसरा घर याद करने का आसान\r\nतरीका है आप इनका जब टोटल करेंगे तो 49\r\nआएगा\r\nजब मुझे दो-चार 11 याद है तो दूसरे की कौन\r\nरोकेगा 14\r\nबनाने के लिए कितना चाहिए\r\nऔर क्योंकि इनको कंपनियों हाउस कहते हैं\r\nजो यह लाइन बीच में आपको दिख रही है\r\nकुंडली में आमने सामने कंपनियां हाउस हम\r\nआगे पढ़ेंगे जब हम आपका गोचर आ ट्रांजिशन\r\nकी बात करेंगे वहां पे कुछ चीज कम आएंगे\r\nइसमें की कैसे कम करते हैं फिलहाल हमें\r\nतीन ही चीज ली है क्योंकि यहां पे तीन दिख\r\nरही हैं एक और कॉन्सेप्ट जितने ज्यादा\r\nप्लैनेट होंगे उतनी और गला स्ट्रांग होगी\r\nमैन लीजिए इस घर में दूसरे घर में तीन\r\nप्लैनेट बैठकर अर्गला दे रहे हैं और 12वीं\r\nघर में केवल एक प्लैनेट है तो यह अर्गला\r\nको पुरी तरह से नहीं रोक पाएगा बहुत कम हद\r\nतक रोक पाएगा तो इसी तरह डिपेंड करेगा की\r\nज्यादा प्लैनेट मिलके स्ट्रांग कर गला\r\nहोती है अब क्वेश्चन ये आएगा आपका की इन\r\nतीन दिन पहले हुए बेनिफिट भी हुए उनका\r\nकैलकुलेशन कर लेंगे कितने मलिका कितने\r\nबेनिफिट हैं दिन में से एक है दो बेनिफिट\r\nहै तो\r\nबेनिफिट्स जरूर होगा कुछ ना कुछ ऊपर नीचे\r\nहोंगी वह आगे समझेंगे जब प्लेनेटरी\r\nइन्फ्लुएंस पूरा समझेंगे\r\nऔर गला का क्लियर है एक बहुत अच्छा\r\nएग्जांपल और लेते हैं यह जो एग्जांपल\r\nइसमें कुछ एडिशनल चीज भी हैं जो थोड़ा सा\r\nबात करना चाहते हैं बस देखिए इस कुंडली\r\nमें 10000 में हम देखते हैं प्रोफेशन के\r\nहाउस में अर्गला कहां-कहां से ए रही है\r\nकुंडली का यह है आपका 10000 क्या दूसरे घर\r\nसे अगला है जी हान वीनस और राहु की अर्गला\r\nहै\r\nविनाश तो स्वामी ग्रह एक बढ़िया अच्छा है\r\nराहु अच्छा है क्या राहु के ऊपर किसी के\r\nरिस्पेक्ट है नहीं है केवल विनाश के साथ\r\nबैठा है और आप यह पिछले में समझ चुके हैं\r\nराहु केतु कम कैसे करते हैं तो दो प्लैनेट\r\nकी अर्गला यहां से आती है\r\nबिल्कुल आएगी चौथे में तीन प्लैनेट बैठे\r\nहैं जुपिटर भी है मून भी है बस केवल एक\r\nसनी रर है या पाप ग्रह बैठा है यानी की\r\nचार प्लैनेट है और एक आपके पास शनि\r\nआपको कोई अगला नहीं दिखेगी यहां पर 11वां\r\nघर मैं कोई प्लानिंग नहीं है क्या इन\r\nअर्गला को कोई रोक रहा है\r\nकुंडली के दसवें हाउस से दूसरे घर की\r\nअर्गला को रोकता है बार-बार यानी की ये\r\nवाला घर आपका नाइंथ हाउस नाइंथ हाउस में\r\nमंगल बैठा है जी हान ये अर्गला को\r\nऑब्स्ट्रक्ट करेगा लेकिन जो की यहां दो\r\nप्लैनेट है ये अकेला है तो पुरी तरह से\r\nनहीं रोक पाएगा चौथे करके अगला को कौन\r\nरोकेगा यहां बैठा प्लान\r\nचौथे के अदला को उसे घर से 10वें घर का\r\nप्लैनेट टूटेगा 10वें घर में कोई नहीं है\r\nऔर चुकी 11वीं घर में अर्गला ही नहीं है\r\nतो तीसरे कट देखने की जरूरत नहीं है तो\r\nहमने ये समझा की यहां पे ये अर्गला\r\nबेसिकली कहां कहां से ए रही है कैसे ऑफसेट\r\nहोंगी हालांकि बंगले इस कुंडली में ये\r\nअलग-अलग रोकने की काबिलियत नहीं रखता\r\nसमझेंगे आगे क्यों नहीं रखता ठीक है अब\r\nइसमें एक क्वेश्चन है अगर मैं आपसे पूछूं\r\nकी ये जतन जो है हालांकि ये अलग-अलग से\r\nथोड़ा सा अलग है कुछ चीज इंवॉल्व होंगी\r\nइसका प्रोफेशन क्या करवा देना चाहिए इसको\r\nकी इसको सक्सेस मिल जाए\r\nउसका लोड देखो कहां बैठा है ये तो अपने घर\r\nमें बैठा है\r\nतो देखो युति किसके साथ है\r\nआप देखोगे शायद सन के साथ है\r\n12th हाउस का ओनर तो बारवी खर्चे संबंधित\r\nकम करवा दो इसको सक्सेस मिल जाएगी\r\nएक्सपोर्ट इंपोर्ट करवा दो\r\nफॉरेन से कुछ कम करवा दो यार समथिंग\r\nसमथिंग डेट यही एक नाम नॉर्मल चीज होती\r\nहैं चलिए क्या और कुछ एक्सपेक्ट है उसका\r\nवो है स्पेक्ट या फिर रिलेशन एक और है\r\nसैटर्न में बैठ के अपनी 10th एक्सपेक्ट से\r\nइनको देखिएगा यानी इसकी सेटिंग के साथ भी\r\nरिलेशन है अब\r\nसैटर्न तो बेनिफिट है\r\nपांचवी घर का मलिक है छठे घर का मलिक है\r\nमूड रिकॉर्ड राशि छठे घर में है\r\nतो इस व्यक्ति के प्रोफेशन को खराब करेगा\r\nयही बोलते हम लोग यही पढ़ा है आम भाषा में\r\nयही समस्या है की भाई सैटर्न दिख जाए तो\r\nसमझ लो दिल कर देगा परेशान कर लेगा कष्ट\r\nदेगा और चूंकि पहले से क्या यहां पर आम\r\nतौर पे यही लॉजिक बनता है\r\nइस चार्ट में एक नजर हम डालते हैं नमन\r\nसैटर्न कहां बैठा है सैटर्न आपको लैंड में\r\nबैठा मिलेगा\r\nसैटर्न 10000 का मलिक है\r\n10थ हाउस पे सैटर्न कर्म का कारक है और\r\nधनी इसको दिल्ली में दसवें घर का मलिक है\r\nसाथ में nauvansh में\r\nराजयोग भी बना रहा है तो क्या इस केस में\r\nइस घर को खराब करेगा\r\nएक और चीज देखते हैं\r\nसैटर्न किसके साथ बैठा है\r\nसेटिंग बैठा है सन के साथ जो है फिफ्थ\r\nहाउस\r\nठीक\r\nहै\r\n12th\r\nमें क्या मरकरी जो की लगने चैट में 10000\r\nके प्रोफिशिएंट का लॉर्ड है\r\nवो गुरु से भी संबंध बनाता है यहां तो आप\r\nदेखेंगे कोई संबंधी बनाता लेकिन आपको कुछ\r\nसंबंध मिलेंगे\r\nठीक है\r\nसेटिंग का संबंध इन दोनों से बनता है और\r\nसेटल है फिफ्थ था उसका मलिक\r\nयानी की फिफ्थ के लौट से भी टेंट हाउस\r\nमें देखेंगे तो\r\nसूर्य जो है वह शनि के साथ में है मरकरी\r\nको देख रहा है जो टेंट हाउस का लॉर्ड है\r\nऔर सूर्य उसके साथ है जो नमाज में 100 था\r\nउसका लॉर्ड है और सूर्य कहां का मलिक है\r\nपांचवे घर का तो क्या पांचवे घर का रोल इस\r\nकुंडली में नहीं आएगा ऐसे प्रोफेशन\r\nक्योंकि सूर्य दोनों जगह मरकरी को देख रहा\r\nहै मरकरी के साथ है दूसरा कर्म का जो मलिक\r\nहै उसके साथ है यहां तो नीचे भांग बनाता\r\nहै और सूर्य और भी कुछ चीजों का कारक है\r\nअब बताएं यह कुंडली किसकी हो सकती है अब\r\nमैं आपको बोलूं की यह कुंडली है\r\nजी हान एमएस धोनी\r\nकहां एक्सपोर्ट इंपोर्ट कहां सपोर्ट\r\nसपोर्ट कहां से आता है\r\nआपको पता है स्पोर्ट्स आता है\r\nस्पोर्ट्स के लिए कारक होते हैं शनि नीचे\r\nभांग राजयोग बनाता है नमाज में दसवें घर\r\nका मलिक है यहां पर दसवें घर पर एस्पेक्ट\r\nडालता है और शनि दशहरे घर पे आधिपत्य है\r\nशनि और कर्म का\r\nलाया जाता है तो इसका मतलब खराब कर देगा\r\nयहां तक ठीक है\r\nअब एक चीज और देखिए\r\nयह जो भी मरकरी है नवाज़ में 7000 में\r\nबैठा है क्या मरकरी पर कोई\r\nआपके पास अगला है\r\nक्या 10000\r\nपर कोई अगला है हाजी वीनस करेला आती है\r\nयहां टेंट हाउस पर भी ए रही है मरकरी पे ए\r\nरही है\r\nलग्न चार्ट पर भी विनाश अगला दल ही रहा है\r\nक्या बिजनेस का कोई रोल नहीं होना चाहिए\r\nइसमें\r\nकहीं तो कुछ भी इंवॉल्व हो जब अर्गला दे\r\nरहा है और डिसाइडिंग फैक्टर कम करेगा तो\r\nवीणा संबंधी कुछ तो मिलना चाहिए जातक को\r\nवीनस कारक किस चीज का है\r\nvinaskarak है आठ का ड्रामा का तो इनके\r\nऊपर एक मूवी बनती है जिसके राइट्स के लिए\r\n45 करोड़ रुपए ले लेते हैं दूसरा आपको पता\r\nहै की एडवर्टाइजमेंट के इनकम यानी की\r\nउसमें एक्टिंग करने के बदले या ब्रांड\r\nप्रमोशन के बदले कितना पैसा लिया जाता है\r\nतो अगर वीणा से इंवॉल्व हुआ है इतने\r\nस्ट्रांग तरीके से अर्गला दे रहा है तो\r\nकहीं ना कहीं कुछ रिजल्ट\r\nभी लिए आप सबको पता होगा\r\nएक और इंटरेस्टिंग चीज है थोड़ा सा लंबा\r\nहो जाएगा सेशन क्योंकि एक्सरसाइज भी अभी\r\nआपके लेकिन फिर भी देख लेते हैं\r\n2002 से 2020 तक\r\nदशा शुरू होती है राहु की\r\n2004 से\r\n2019 तक महेंद्र सिंह धोनी इंडियन टीम में\r\nरहते हैं यह उनके कैरियर का सबसे पीस टाइम\r\nऔर यह दशा राहु की कोई बताया इस कुंडली\r\nमें राहु का रोल कहां से है प्रोफेशन को\r\nलेके\r\nनीचे भांग राजयोग बन रहा है सूर्य होता\r\nशनि होता समझ में आता मरकरी होता समझ में\r\nआता मरकरी लगने चैट में 10th का हुनर है\r\nराहु क्यों\r\nअगला है कुछ राहु की लग्न चार्ट में\r\nदेखेंगे तो सेकंड हाउस में अर्गला है और\r\nराहु वीनस के साथ बैठा है स्वामी ग्रह के\r\nसाथ बैठा है स्पष्ट है अगर\r\nयहां देखेंगे आप\r\nनमन तो यहां आपको मरकरी दिखेगा मरकरी पे\r\nआप देखेंगे की यह और गला स्टॉप हो रही है\r\nवह मंगल और राहुल इसको रोक देंगे लेकिन\r\nक्योंकि मैंने बताया की इसको दिल्ली में\r\nमंगल रोकने लायक नहीं है यह अगले सेशन में\r\nकर लेंगे क्योंकि थोड़ा सा बड़ा हो जाएगा\r\nठीक है\r\nअपनी कुंडली में अर्गला देखने मत बैठ जाइए\r\nक्योंकि कुछ चीज रह गई है पुरी तरह से\r\nसमझेंगे कब कोई प्लानिंग रोक सकता है नहीं\r\nरोक सकता लेकिन इतना समझ में आएगा अगला कम\r\nकरती है बहुत इंपॉर्टेंट होती है और जरूरी\r\nहो जाता है की उनको एनालिसिस करें अभी\r\nएक्सरसाइज है आपके"},{"topic":"कुंडली अध्ययन-सम्पूर्ण ज्योतिष - (Part 7)-सीखिए सम्पूर्ण पराशरी ज्योतिष-A New Beginning-","text":"है तो आज हम लोग एक जातिका का चार्ट\r\nएनालिसिस करने वाले kundaliy अध्ययन और\r\nविवाह संबंधी प्रिडिक्शन करेंगे और हमने\r\nजो भी पड़ा है अभी तक अपने कोर्स में उसको\r\nअप्लाई करने की कोशिश करेंगे तो गौर से और\r\nबहुत अच्छे से समझने का चार्ट को ठीक है\r\nचलिए\r\nदेखिए एक जातिका का ये चार्ट है फीमेल है\r\n1979 का यह बर्थ था और यह लग्न चार्ट है\r\nकुंडली आपके सामने है तो अभी हम बेसिक से\r\nस्टार्ट करेंगे जो हमने केवल पढ़ा है तो\r\nविवाह के लिए हम देखते हैं 7000 तो सबसे\r\nपहले मेरी नजर जाएगी सेवंथ हाउस पर जहां\r\nपर छह नंबर राशि लिखी हुई 6 नंबर राशि है\r\n12वीं घर को देखिए आपको मरकरी यहां मिल\r\nजाता है तो गलत घर में बैठा है कोई बात\r\nनहीं क्या इसके ऊपर कोई एस्पेक्ट है या\r\nकंजन है जी केतु के साथ बैठा है बेनिफिट\r\nप्लैनेट है अभी बाकी दोनों की हम बात नहीं\r\nकर रहे एस्पेक्ट है किसी की देखते हैं\r\nसातवें घर से यानी की छठे हाउस में 6 हाउस\r\nजो है वहां पर शनि है राहु है और दोनों की\r\nएक्सपेक्ट बुध के ऊपर पड़ेगी हालांकि सबके\r\nऊपर पड़ेगी लेकिन अभी हम बात कर रहे हैं\r\nविवाह स्थान से संबंध तो यह दोनों प्लैनेट\r\nबुध को देखेंगे और क्योंकि राहु शनि के\r\nसाथ है तो रिजल्ट भी सनी के देगा शनि का\r\nकम होता है दे लेकर\r\n6000 का ओनर शादी करता है तो उसकी दशा\r\nशादी होगी तो हम देखते हैं बुद्ध की दशा\r\nइस कुंडली के कब आने वाली है अब मरकरी का\r\nजो महादशा शुरू होगी वो होगी 2065 में जब\r\nयह जाती का 8586 साल की हो चुकी होगी तो\r\nयह कम नहीं करने वाला तो चलिए एक बार अभी\r\nतक हम आगे इसलिए नहीं पढ़ रहे क्योंकि\r\nहमने केवल 7000 पढ़ाया है की ये विवाह के\r\nलिए होता है आगे इसमें नमन जो है इसका उसे\r\nपर नजर डालते हैं तो अब 9 मार्च\r\nका लॉर्ड कौन है\r\n12 नंबर राशि जो है गुरु गुरु आपको लगने\r\nमें बैठा हुआ मिलेगा चलिए ठीक है अब\r\nक्योंकि एक तो गुरु शनि के साथ बैठा है\r\nयहां पर\r\nतो इसका शत्रु है क्योंकि तात्कालिक अगर\r\nआप देखोगे नेतृत्व शत्रु है तो गुरु की जो\r\nराशि है 12वीं राशि यह शत्रु राशि हुई और\r\nशनि लगने से बैठकर इसको भी देखेगा 7थ हाउस\r\nको यानी लग्न चार्ट में भी शनि 7थ हाउस के\r\nलॉर्ड को देख रहा है और नवस में 7थ हाउस\r\nके लौट के साथ बैठा है उसे भाव को भी देख\r\nरहा है तो इसका मतलब यह कंफर्म है की जाती\r\nका व्यवहार लेट होने वाला है चलिए अब\r\nक्योंकि इस नवाज़ के हिसाब से गुरु शादी\r\nकर सकता है सेवंथ हाउस का लॉर्ड है तो\r\nगुरु के दशा चेक कर लेते हैं\r\nजुपिटर की दशा आपके स्टार्ट होगी 2030 जब\r\nयह जाती का 51 साल की हो जाएगी 51 ईयर तो\r\nकम तो यह भी नहीं करने वाला अब हम थोड़ा\r\nसा आगे बढ़ते हैं अब देखते हैं क्या कोई\r\nहाउस का माइंड कर सकते हैं तो जी हान\r\nविवाह के लिए हम सेकंड हाउस को 7000 से\r\nकंबाइन करते हैं क्यों करते हैं 7000 आपका\r\nपरिवार का कुतुब का तो विवाह यानी मैरिज\r\nका मतलब होता है कोई नया पर्सन आपके\r\nपरिवार में ऐड हो जाना\r\nतो अब देखते हैं की इस कांबिनेशन के हिसाब\r\nसे ये मैरिज कब होनी चाहिए तो 7000 में आप\r\nदेखोगे सॉरी सेकंड हाउस में आप देखोगे सात\r\nनंबर राशि यह राशि है\r\nतो शादी हो सकती है तो हम पैरेंट देख लेते\r\nहैं\r\nजब ये 10 साल की थी तो ना तो अब जुपिटर\r\nमें\r\nगुरु की दशा आने वाली है क्योंकि यह 2030\r\nके बाद आएगी और यह 89 में खत्म हो गई है\r\nकोई बात नहीं है फिर से अपने लक्ष्य चार्ट\r\nपर आते हैं क्योंकि हमने लग्न चार्ट से\r\nदूसरे और सातवें का संबंध नहीं देखा अभी\r\nतक क्योंकि हमने पढ़ा नहीं था इस स्टेप\r\nमें हमने इंवॉल्व किया आगे उसको चलिए\r\nहमारा\r\nपता है मरकरी ये शादी देने की कैपेबिलिटी\r\nरखता है दूसरे घर का स्वामी है मेरा मंगल\r\nयानी की मंगल के साथ जब बुद्ध की दशामा\r\nदशा होगी तो उसमें शादी हो सकती है अब\r\nचूंकि बुध की दशा तो बहुत लेट आएगी तो में\r\nआएगी पहले मंगल की दशा उसमें बुध की ए जाए\r\nतो शादी हो जाएगी पर क्या ऐसा हो जाएगा\r\nऐसे साथ बहुत सारी कुंडली में आपको दिखेगा\r\nकी दो और सांप की कांबिनेशन से विवाह नहीं\r\nहो रहे अगर यह अप्लाई होता है फंडा तो हर\r\nजगह अप्लाई होना चाहिए तो थोड़ा सा आगे\r\nबढ़ते हैं इसी कॉन्सेप्ट में देखिए\r\nकुछ याद आया किसी को\r\nएक्जेक्टली\r\nआखिरी प्लैनेट देखिए जो है मार्च और हमने\r\nलास्ट क्लास में पढ़ा है व्हाट इस दी के\r\nदी के इस धारा कारक यानी की स्पाउस का\r\nकारक यानी की मुझे क्लियर है की एक तो\r\nमंगल सेकंड हाउस का लौड़ा है जो रोल\r\nनिभाएगा दूसरा इस कुंडली के लिए मंगल\r\nस्पाउस का कारक है यानी धारा कारक है तो\r\nमहत्वपूर्ण रोल मंगल का हो जाता है इस\r\nकुंडली में तो क्या प्रिडिक्ट कर दे की\r\nमंगलमय मंगल की महादशा में बुद्ध की दशा\r\nआएगी तो शादी हो जाएगी\r\nइतनी जल्दी क्या है\r\nअभी कन्फर्मेशन करते जाएंगे एक अच्छा\r\nएस्ट्रोलॉजर रखना योग नहीं बताता वह समय\r\nबताता है देखते हैं कैसे अब मैंने लग्न\r\nचार्ट पर देखा सातवें घर का मलिक कौन बुध\r\nहै 9 मार्च\r\nलेकिन अगर आप देखोगे गौर से तो यह बंडल के\r\nनामांस में है और 9 मार्च में ग्रह कैसे\r\nजाता है यह भी हमने लास्ट क्लास में\r\nपढ़ाया और इंपॉर्टेंट क्यों है क्यों यहां\r\nपर मंगल इंपॉर्टेंट हो गया ये हमने लास्ट\r\nक्लास में समझा की naumaunch बनता कैसे है\r\nयानी नमन मुझे बता रहा है की बुद्ध के कम\r\nकरने के लिए मंगल इंपॉर्टेंट है अब नुमाइश\r\nमें मंगल कहां बैठा है\r\nतो आपको मंगल मिलेगा दूसरे घर में और\r\nदूसरा घर है आपका कुटुंब का परिवार का\r\nयानी की लग्न चार्ट आपको बताता है की मंगल\r\nसकेंगे उसका मलिक है मंगल धारा कारक है\r\nइसलिए इंपॉर्टेंट है नमन साहब को बता रहा\r\nहै की मंगल दूसरे घर में बैठा है और बुद्ध\r\nमंगल के नौ मांस में है यहां से आपको 4\r\nकन्फर्मेशन मिलते हैं मंगल की\r\nस्ट्रेंथ के लिए\r\nअब आते हैं क्योंकि ये कुंडली हमारे पास\r\n2007 में आई तो हम उसे समय का एनालिसिस\r\nकरते हैं की उसे समय क्या-क्या चीज हो\r\nसकती हैं तो आप मुझे पता है की यह विवाह\r\nकब होगा एक तो यह है की मंगल बहुत प्रबल\r\nयोग बनाएगा इस विवाह के लिए क्योंकि चार\r\nयोग मिल रहे हैं चार संभावनाएं दे रहे हैं\r\nचलिए आगे बढ़ते हैं मंगल में बुध होना\r\nचाहिए क्योंकि बुध सातवें घर का मलिक है\r\nतो मुझे टाइम पीरियड मिल गया क्या मैं\r\nप्रिडिक्ट कर डन की 18 जुलाई 2008 से लेकर\r\n15 जुलाई 2009 तक के बीच में इस जाती का\r\nका विवाह हो जाएगा पर एक साल का पीरियड\r\nएस्ट्रोलॉजी के हिसाब से बहुत ज्यादा है\r\nमैं थोड़ा सा आगे देखता हूं\r\nके बारे में कुछ पढ़ा था अगर किसी को याद\r\nहो तो गौर से देखो\r\nबुद्ध जो है वह 1 साल का पीरियड है यहां\r\nपर\r\nलेकिन मरकरी या बुद्ध कौन सी राशि में\r\nलग्न चार्ट मैं यह 11वीं नंबर राशि में है\r\nऔर 11वीं नंबर राशि जो है वह होती है आपकी\r\nसंशोधन राशि में बैठा ग्रह अपना प्रभाव\r\nशुरू के आधे भाग में सबसे ज्यादा देता है\r\nयानी की जोली से लेकर पहले 6 महीने हैं तो\r\nमैं मानूं की दिसंबर 2008\r\nदिसंबर 08 तक विवाह\r\nराशियां पड़ी हुई है उनका उसे करना पड़ता\r\nहै आगे बढ़ते हैं\r\nअब जब मैंने इसमें दशा देखी की शुरू की 6\r\nमहीने में मुझे और क्या मिल रहा है तो\r\nमुझे देखा की मार्स के अंदर मरकरी तो है\r\nलेकिन साथ में वीनस भी है और वीनस नैसरगी\r\nकारक है विवाह का यह हमने पढ़ा है और अब\r\nडेट मेरे पास निकल के आता है की ये जो\r\nटाइमिंग है वो ये दो महीने का है यानी की\r\n30 सितंबर को हटा डन तो एक अक्टूबर से\r\nलेकर 29 नवंबर यानी अक्टूबर का महीना है\r\nमेरे पास और नवंबर का महीना है तो क्या\r\nप्रिडिक्शन कर दे की\r\nशादी हो जाएगी\r\nअच्छा एस्ट्रोलॉजर और एनालिसिस करता है\r\nआगे बढ़ते\r\nहैं\r\nवीणा से नवी नंबर राशि में यानी की 10000\r\nमें आपको बिजनेस मिलेगा\r\nनवीन राशि होती है आपकी प्रस्तुत राशि\r\nइसमें बैठा ग्रह अपने प्रभाव वाद के समय\r\nमें देता है तो अगर यह दो महीने का टाइम\r\nहै एक अक्टूबर का और एक नवंबर का तो क्या\r\nमैं बोल सकता हूं की बिजनेस की प्रबल\r\nसंभावनाएं बनेगी नवंबर के महीने में\r\nइस महीने में शादी हो जाएगी यह तो बहुत\r\nक्लोज प्रिडिक्शन हो गया\r\nपर नहीं क्योंकि अच्छा स्ट्रॉलर झील\r\nकिया है क्या वो मैच होता है आगे बढ़ते\r\nहैं तो मुझे पता है की नवंबर की बात मुझे\r\nकरनी है मेरे हिसाब से कैलकुलेशन के हिसाब\r\nसे यह दशा का पीरियड लिखा हुआ है आपका\r\nमार्च पर करिए सारी चीज जो हम इसका\r\nएनालिसिस कर रहे हैं दो महीने का चलिए तो\r\nहमने क्या किया सबसे पहले हमने 1 नवंबर\r\n2008 का एक गोचर या ट्रांजिशन का चार्ट\r\nबना लिया यह थोड़ा सा डिस्कस कर चुके हैं\r\nपूरा दीप में जाएंगे आगे है ना ये आपको\r\nसमझ में ए गया ना कैसे फिट करते हैं इसको\r\nअपने लग्न चार्ट पे गोचर निकलने के बाद जी\r\nहै तो मुझे दिखा की यार अगर मैं 8 थाउसेंड\r\nदेखूं मैंने सारे ग्रह मेंशन नहीं किए\r\nसॉरी एक था उसमें मुझे मंगल और बुद्ध की\r\nयुति दिख रही है जो मुझे चाहिए शादी के\r\nलिए अच्छी बात है\r\nपर क्या ये पूरा 100% रिजल्ट देने के लिए\r\nतैयार है थोड़ा सा एनालिसिस और करेंगे\r\nक्योंकि अच्छा एस्ट्रोलॉजर जी देखिए पहले\r\nतो ये दोनों तरह उसमें है एक था उसे\r\nकुंडली का सबसे ज्यादा खराब ग्रह घर और यह\r\nदेता है ऑब्स्ट्रक्शन बढ़ा है परेशानी है\r\nपहली चीज दूसरी चीज मंगल nationalgik रूप\r\nसे बुद्ध को अपना शत्रु मानता है और साथ\r\nमें बैठे हैं तो तात्कालिक शत्रु हो गए\r\nयानी की atishatru यानी मंगल ट्रिप भाव\r\nमें बैठा एक तो जो प्रबल दावेदार है ना\r\nइसका आने का उत्तरी का भाव में बैठा है और\r\nअति शत्रु के साथ\r\nएक कांबिनेशन यहां बना तो बने कांबिनेशन\r\nदेखा मैंने देखा आस पास कोई और गोचर बनता\r\nहै थोड़ी सी मेहनत करनी पड़ेगी अच्छे\r\nरिजल्ट देने के लिए ठीक है एक गोचर हमने\r\nऔर निकाला\r\n20 तारीख दल दिया हुआ है 20 के क्वेश्चन\r\nमें मुझे क्या दिखा अब गौर से देखिए\r\nअब तीनों ग्रह फिर से ये है अब यह है\r\nनाइंथ हाउस में यानी अब ये ट्रिक हाउस से\r\nबाहर है लेकिन क्या मंगल अब बुध के साथ\r\natishhatru नहीं है बिल्कुल है लेकिन जो\r\nकी मंगल जो प्रबल दावेदार है विवाह का वो\r\nएक तो एक भाव से बाहर निकल आया और गौर से\r\nदेखिएगा किसकी राशि में है वह अपनी राशि\r\nमें है यानी की अब वो बहुत बलवान है और\r\nदूसरी उसकी वो राशि कुंडली के सबसे अच्छे\r\nघर यानी की नाइंथ हाउस में है तो मंगल\r\nबहुत बाली हो गया यहां पर तो अब चाहे वो\r\nअति शत्रु के साथ में है लेकिन पिछले गोचर\r\nसे यह गोचर बहुत अच्छा है एक चीज और से और\r\nनोट कीजिएगा अगर आप समझ सके\r\nतो हमने देखा की नमन कुंडली में जो 7 था\r\nउसका लॉर्ड है मेरा लिख देता हूं वो था\r\nजुपिटर\r\nठीक है और 9 मार्च कुंडली में सेकंड हाउस\r\nका लॉट था विनर याद होगा आपको अभी हमने\r\nदेखा क्या इस गोचर में 20 तारीख के गोचर\r\nमें इनका कहीं संबंध है देखेगा गोद से\r\n10000 उसमें आपको जुपिटर और वीनस का गोचर\r\nमिलेगा sathmen यानी 9 मार्च का चार्ट\r\nआपको बता रहा था की इन दोनों के कांबिनेशन\r\nसे मैरिज हो जाएगी तो यहां वो गोचर बनता\r\nहै अब एक चीज और एक्सप्लेन करना चाहूंगा\r\nवीनस को यहां पे हमने दशा में क्यों\r\nइंपॉर्टेंट माना केवल इसलिए नहीं की वीनस\r\nविवाह कारक है इस कुंडली में बिजनेस का\r\nबहुत महत्व है क्योंकि हमने वो टॉपिक कवर\r\nनहीं किया अगर वो कर लेते तो आप स्पष्ट\r\nरूप से बोल सकते द की यह सबसे स्ट्रांग\r\nकांबिनेशन बनने वाला है हम आगे पढ़ेंगे तो\r\nआगे और समझेंगे कैसे बिजनेस में बहुत\r\nमहत्वपूर्ण है ठीक है तो अभी आई होप\r\nक्लियर है तो अभी मैं जाके के लिए क्या\r\nबोलने वाला हूं\r\nमेरा गोचर 20 तारीख के आसपास का सबसे\r\nअच्छा बैठा है हो सकता है 18 19 का हो या\r\nआगे पीछे का हो तो क्या मेरी डेट में जातक\r\nको दे सकता हूं की 15 तारीख से लेकर 29\r\nतारीख मात्रा 15 दिनों में सबसे प्रबल योग\r\nहै और निश्चित होना चाहिए क्यों क्योंकि\r\nमंगल बुध और शुक्र तीनों का व्यक्ति है\r\nनवंबर में होती है सबसे अच्छे घर में मंगल\r\nपूरा बलवान और नामांक के जो ग्रह हैं\r\nदोनों जो जरूरी है शादी के लिए उनकी युति\r\nभी टेंट हाउस में बन रही है तो इस पूरे\r\nचार्ट में हमने क्या-क्या एनालिसिस किया\r\nकुछ लोग बोलेंगे की ये तो दूसरा और सातवां\r\nघर लगने चैट कर देख के एनालिसिस हो जाता\r\nबिल्कुल हो जाता तो क्या हर चैट में दूसरे\r\nऔर सातवें के कांबिनेशन से शादी हो जाती\r\nहै नहीं होती इसलिए\r\nमंगल के घर में है\r\nयानी मंगल का रोल बहुत इंपॉर्टेंट है\r\nदूसरा मंगल लग्न चैट में सेकंड है उसका\r\nमलिक है मंगल धारा कारक भी है और 9 मार्च\r\nमें मंगल सेकंड हाउस में बैठा है तो चार\r\nरीजन मिलते हैं मुझे मार्स प्रेक करने के\r\nठीक है पहला अब क्योंकि मैंने धारा कारक\r\nचार्ट्स लगन चैट से निकाला है तो मैं लग्न\r\nचैट में 7000 का मलिक कौन है मरकरी तो\r\nमेरे लिए मरकरी इंपॉर्टेंट हो जाएगा\r\nवीनस चुकी अभी हम केवल इसलिए मैन रहे हैं\r\nकी शादी का कारक है जो की इस कुंडली में\r\nएक और बहुत इंपॉर्टेंट चीज भी हम आगे\r\nडिस्कस करेंगे तो यहां पर बिजनेस का\r\nकांबिनेशन आया तो हमने 9 मार्च को उतना\r\nइंपॉर्टेंट दिया क्योंकि यह बताया की क्या\r\nमंगल का रोल वास्तव में इंपॉर्टेंट है आप\r\nयाद रखिएगा आपने क्या पढ़ा था नमन केवल\r\nशादी के लिए उसे नहीं होता 9 मार्च आपकी\r\nकुंडली और स्ट्रेंथ बताता है की जो पोजीशन\r\nलग्न में है क्या बन रही है अब क्योंकि\r\nशनि विवाह लेट कराएगा लगने के हिसाब से तो\r\nअपना मंच में भी देखें की हान यह कंफर्म\r\nकर रहा है यानी की विवाह लेट होगा और इस\r\nजाती का क्या विवाह जो हमने डेट दिया 15\r\nसे लेकर 29 तक तो 22\r\n1108 विवाह संपन्न हुआ ठीक है एग्जैक्ट से\r\nडेट को\r\nबात ये नहीं है की आप कितना से ठीक करते\r\nहो बात ये है की जब आप एनालिसिस करते हो\r\nतो आर यू सेटिस्फाइड क्या आपको\r\nसेटिस्फेक्शन मिलता है की आपके पास इतने\r\nलॉजिक है की मैं क्यों यह डेट दे रहा हूं\r\nदूसरा सांप का दशा दर्शन देख के केवल योग\r\nबता देने से कम नहीं होगा कुंडली में ठीक\r\nहै\r\nअगर नहीं किया तो आप लोग ना यही सीमित रह\r\nजाओगे बस आप धारा कारक देखोगे और ऐसे मैच\r\nकर रहे होंगे तो जब तक दो से तीन अलग-अलग\r\nचीज डिस्कस नहीं हो जाएंगी तब तक आपकी थॉट\r\nप्रक्रिया खुलेगी नहीं और ये पूरा धंधा\r\nनॉलेज के साथ-साथ है की आप कैसे चीजों का\r\nअप्लाई करना सीखते हो कांबिनेशन बना के\r\nदेखोगे अभी क्वेश्चन है मेरा आप लोगों से\r\nये आपका होमवर्क समझ लीजिएगा आप जो आपके\r\nसामने आने वाला है ठीक है अच्छा क्वेश्चन\r\nदेखिए क्योंकि हमारे पास एक कुंडली 2007\r\nमें आई लेकिन मुझे बताइए\r\nमंगल धारा कारक हो गया\r\nइंपॉर्टेंट है और बुद्ध भी मंगल के दौरान\r\nहै तो पहली प्रायोरिटी मंगल हो गई चलिए\r\nमैन लेते हैं लेकिन नमन में जुपिटर भी तो\r\n7000 का लोड है तो अगर मार्स के अंदर\r\nजुपिटर ए जाए तो शादी क्यों नहीं होगी और\r\nइस चलो अब आप बोलोगे की लग्न चार्ट मैं\r\nबुद्ध से में प्लैनेट तो चलो मार्स के\r\nअंदर जुपिटर के अंदर अगर मरकरी ए जाए\r\nहै तो क्यों नहीं होगी देखते हैं क्या\r\nक्या दशाएं हैं\r\nहम देख चुके\r\nमंगल के अंदर जुपिटर चला है 2006 से 2007\r\nके बीच में एक और कांबिनेशन आपको देते हैं\r\nमंगल के अंदर जुपिटर के अंदर मरकरी चलाएं\r\nदो महीने 11 दिसंबर 11 अक्टूबर 2006 से 29\r\nनवंबर 2006 तक अब आपके लिए होमवर्क ये है\r\nकी अगर यह प्लैनेट इंपॉर्टेंट है तो इस\r\nदशा में जाती का की शादी क्यों नहीं हुई\r\nऔर ये इसलिए इंपॉर्टेंट है की अगर ये\r\nकुंडली 2005 में आई होती तो क्या हम यह\r\nप्रिडिक्शन देते समझी टाइम निकल गया\r\nकी क्या हम केवल योग बता देंगे क्या इस\r\nयोग में हो जाएगी फिर नहीं हुई तो हम उसको\r\nअगला योग बता देंगे क्या यह सही तरीका है\r\nप्रिडिक्शन का या हम समझे की सबसे\r\nइंपॉर्टेंट चीज क्या है क्या चीज मायने\r\nरखने वाली है\r\nआप लोग समझ के आएंगे की रीजंस क्या है\r\nसमझ में आया होगा की एक प्रिडिक्शन लेवल\r\nपर पहुंचने में मेहनत करनी पड़ती है अच्छा\r\nदीप एनालिसिस करना पड़ता है और वो करने के\r\nबाद आपको बहुत सेटिस्फेक्शन मिलेगा तो\r\nचलिए अब आपका नेक्स्ट क्लास में इसको\r\nडिस्कस करते हो और एक"},{"topic":"गाइडलाइन-कुंडली अध्ययन-Part-9 -How to Predict Marriage-Complete Guideline -सम्पूर्ण ज्योतिष","text":"यह क्लियर है ओके\r\nदेख लेते आज का हमारा टॉपिक\r\nआपके पास एक कुंडली एक लग्न चार्ट आता है\r\nजिसमें जातक आपसे विवाह संबंधित प्रश्न\r\nकरता है ऐसी स्थिति में आप क्या करेंगे\r\nकैसे एनालिसिस करेंगे और कैसे जातक को\r\nआंसर देंगे इस संबंध में आज हम हर चीज\r\nडिटेल में समझने वाले हैं यह पूरा अपने आप\r\nमें एक चैप्टर है जहां हम समझेंगे की\r\nमैरिज का प्रोडक्शन करने के लिए क्या-क्या\r\nकांबिनेशन कम आते हैं किन-किन जाट को\r\nदेखना पड़ता है कैसे प्रिडिक्ट करना है\r\nसबसे पहले जब कुंडली आपके सामने आएगी तो\r\nआपके पास होगा लगने चार्ट तो लग्न चार्ट\r\nमें हम क्या-क्या देखेंगे\r\nजैसे की हम सबको पता है पहला कांबिनेशन\r\nक्या बनता है दूसरे घर का स्वामी और\r\nसातवें घर के स्वामी की दशा अंतर्दशा में\r\nविवाह हो जाता है यहां इसके बारे में हम\r\nपहले ऑलरेडी स्टडी कर चुके हैं एक हमने\r\nएग्जांपल लिया था चार्ट में तो वह एनालाइज\r\nकिया है क्या इसके अलावा और कोई भी\r\nकांबिनेशन होता है जो विवाह दे सकता है\r\nजी हान अगर मैं कहूं की क्या धारा कारक की\r\nदशा अंतर्दशा और सेवंथ हाउस के दशा\r\nअंतर्दशा में विवाह हो सकता है तो जवाब है\r\nहो सकता है क्यों\r\n7000 मैरिज का यह आपको बताया इवेंट यानी\r\nकी प्रॉमिस करेगा\r\nये कारक है पत्तियां पत्नी का यानी किस\r\nहोगी शादी वो एश्योर करेगा आपका दारा कारक\r\nतो इन दोनों के दशा अंतर्दशा में भी शादी\r\nविवाह हो सकता है क्या इनके अलावा कोई\r\nकांबिनेशन बनता है\r\nदूसरे घर में और सातवें घर\r\nमें कोई ग्रह बैठे हैं तो क्या उनकी दशा\r\nअंतर्दशा में विवाह हो\r\nइसका भी जवाब है हान हो जाएगा लेकिन याद\r\nरखिए यह जो कांबिनेशन है यह एक वीक\r\nकांबिनेशन है इसे स्ट्रांग कांबिनेशन नहीं\r\nमाना जाएगा ये स्ट्रांग कब बनेगा जब ये दो\r\nग्रह ये जो दो प्लैनेट हैं जो उसमें बैठे\r\nहुए हैं यह बेनिफिट हो पूर्ण बाला बाल के\r\nसाथ बैठे हो पहली चीज दूसरी चीज या इनकी\r\nदशा अंतर्दशा में इनको कोई सपोर्ट मिल जाए\r\nअब सपोर्ट किस चीज का या तो धारा कारक के\r\npratiyantra दशा ए जाए मेल कुंडली में\r\nबिजनेस का साथ मिल जाए फीमेल कुंडली में\r\nजुपिटर का साथ मिल जाए\r\nतो यह कांबिनेशन स्ट्रांग हो सकता है\r\nadervise यह कांबिनेशन पहले दोनों\r\nकांबिनेशन के कंपैरिजन में वीक माना जाता\r\nहै लेकिन हम इसको पुरी तरह से नाइट नहीं\r\nकरने वाले\r\nफिर आता है हमारे पास क्या फर्स्ट हाउस और\r\n7000 कांबिनेशन मैरिज दे सकता है\r\nफर्स्ट हाउस है आप\r\nlagnot यानी की आप 7000 मैरिज यानी की\r\nइसका मतलब हुआ आपकी मैरिज तो क्या यह\r\nकांबिनेशन अकेले मैरिज दे सकता है जवाब है\r\nनहीं क्यों\r\nमैरिज क्योंकि चार्ट आपका ही है तो फर्स्ट\r\nहाउस का होना कुछ वैल्यू ऐड नहीं करेगा\r\nलेकिन यहां पॉइंट रखा इसलिए की अगर मैन\r\nलीजिए किसी कुंडली में लग्न की महादशा चल\r\nरही है फर्स्ट हाउस की महादशा है तो क्या\r\nमैं उसे पीरियड को छोड़ दूंगा जी नहीं\r\nफर्स्ट था उसकी दशा में सेवंथ हाउस की\r\nअंतर्दशा हो और अत्यंत दशा में अगर मुझे\r\nकोई सपोर्ट मिल जाए वही या धारा कारक का\r\nसपोर्ट हो जाए या वीनस या जुपिटर का हो\r\nजाए और बहुत बिलावल के साथ हो तो यह\r\nकांबिनेशन बनेगा\r\nक्योंकि अगर फर्स्ट हाउस की महादशा है तो\r\nमहादशा का इफेक्ट 70% होता है ठीक बच्चा\r\n30% में बाकी सारी चीज आएंगे तो क्या 30%\r\nबारिश कर सकता है नहीं तो उसके लिए जब बाल\r\nज्यादा होगा प्राणी ज्यादा ताकतवर होंगे\r\nतो वो हो सकता है कांबिनेशन भर के 50% के\r\nलेवल तक ए जाए जहां मैरिज संभव है तो इस\r\nतरह से कैलकुलेशन थोड़े से देख लेंगे अब\r\nक्या इनमें से कोई कांबिनेशन मुझे अच्छा\r\nमिल जाता है तो मैं प्रिडिक्शन कर सकता\r\nहूं जवाब ही नहीं क्योंकि हम जानते हैं की\r\nलग्न चार्ट की स्ट्रेंथ को चेक करने के\r\nलिए आपको जाना पड़ेगा नवमांश पे तो जो भी\r\nआपको\r\nदेखोगे की क्या वह ग्रह\r\nसे संबंध रखते हैं या स्पष्ट हो जाएगा तो\r\nपहला तरीका हमने चार्ट देखा और यह केवल\r\nआपका पहला स्टेप है\r\nहै इसके अलावा दूसरा स्टेप क्या है दूसरा\r\nस्टेप है इस सब को करने के बाद यह\r\nकांबिनेशन देखने के बाद अब हम ए जाएंगे\r\nदूसरा घर ये रहा आपका दूसरा घर कुंडली में\r\nसातवां ये रहा सत्व घर तो क्या यह दोनों\r\nकी प्लैनेट की दशा अंतर्दशा में विवाह हो\r\nजाएगा आंसर फिर से हान हो जाएगा तो अगर ये\r\nकांबिनेशन मिलता है या फिर क्या इसके\r\nअलावा हमें कोई और कांबिनेशन मिल सकता है\r\nदेखिए\r\nसे प्लैनेट इन सेकंड एंड सेवंथ हाउस जो की\r\nयह कांबिनेशन थोड़ा वीक माना जाता है\r\nइसमें वही सपोर्ट चाहिए होगा जिसकी बात\r\nहमने abhilagdh कुंडली में देखते हुए कही\r\nकी दूसरे और सातवें घर में बैठे हुए\r\nप्लैनेट की दशा या अंतर्दशा में विवाह तब\r\nहोगा जब इसको किसी तरह का सपोर्ट मिल\r\nजाएगा चाहे धारा कारक हो या और कोई भी हो\r\nअब मैन लीजिए आपको नौ मांस में एक\r\nकांबिनेशन मिल गया तो क्या मैं अकेले\r\nnaumaish के बेस पर ये बोल सकता हूं की\r\nमैरिज हो जाएगी बिल्कुल नहीं इस 9 मांस के\r\nग्रहों को आप फिर वापस देखेंगे अपने लगने\r\nचैट में अगर आप कांबिनेशन नमन से बना रहे\r\nहैं मिल गया आपको तो मत bhuliyega की आपको\r\nलग्न चार्ट में चेक करना है की क्या इन दो\r\nग्रहों की स्थिति ऐसी है की यह विवाह से\r\nसंबंध रखते हैं और यह हम सब क्यों कर रहे\r\nहैं क्योंकि हमें केवल दशा नहीं बतानी\r\nहमें बेस्ट पॉसिबल\r\nकी प्रबल दावेदार ढूंढना है विवाह करने का\r\nतो हमने 9 मार्च देख लिया हमने लग्नेश देख\r\nलिया\r\nक्या इसके अलावा और कोई तरीका होता है\r\nजहां से मेरे पास कांबिनेशन निकल के आएंगे\r\nदेखते हैं\r\nअब यह चंद्र कुंडली कहां से ए गई हम बात\r\nतो लगने चैट की करते हैं उसका nomanch\r\nबनाते हैं\r\nदेखिए सबसे ज्यादा इंपॉर्टेंट हम किस चीज\r\nको देते हैं दशाओं में\r\nयह तो हम सब जानते हैं\r\nऔर यह भी जानते हैं की दशा आती कैसे है\r\nबनती कैसे है चंद्रमा से कितने लोगों को\r\nनहीं पटरी का संबंध चंद्रमा से है कोई\r\nअच्छा पहले से भी समझ लेते हैं क्योंकि अब\r\nस्टार्ट किया है तो कवर कर लेते हैं चलिए\r\nदेखिए\r\nएग्जांपल ले लेते हैं आपका जन्म हुआ\r\nआपके जन्म के समय\r\nमून\r\nअश्विनी नक्षत्र में है ठीक है आपका जब\r\nजन्म हुआ तो उसे समय चंद्रमा अश्विनी\r\nनक्षत्र में है अश्विनी नक्षत्र का स्वामी\r\nकौन है\r\nकेतु सबको पता है ठीक है तो आपकी पहली दशा\r\nजीवन की जो आएगी जन्म से शुरू होगी वह\r\nकिसकी होगी\r\nकेतु की होगी लेकिन कितने साल की होगी अब\r\nकेतु की दशा तो होती है 7 साल की लेकिन\r\nक्या पूरे 7 साल की चलेगी नहीं आपने देखा\r\nकी आपकी कुंडली में चंद्रमा 15 डिग्री चल\r\nचुका है पुरी राशि होती है 30 डिग्री की\r\nजिसमें से 15 डिग्री निकल गए यानी की जो 7\r\nसाल की दशा है राहु की उसमें से आदि दर्शन\r\nनिकल गई तो जिस दिन आपका जन्म हुआ उसमें\r\nसे अब 3:30 साल निकल गए यानी की अब आपके\r\nजीवन में आगे आने वाले 3:30 साल में आपकी\r\nदशा चलेगी केतु की फिर किसकी ए जाएगी फिर\r\nबिजनेस किया जाएगी फिर आपकी सूर्य की ए\r\nजाएगी इस तरह से दशा चलती हैं तो इसका\r\nमतलब\r\nपुरी तरह से निर्भर करती है चंद्रमा कहां\r\nहै यह चीज क्लियर है\r\nजब मैं दशा चंद्रमा के हिसाब से ले रहा\r\nहूं तो क्या चंद्र कुंडली महत्वपूर्ण नहीं\r\nहो जाती बिल्कुल होती है अब अगला प्रश्न\r\nयह की चंद्र कुंडली बनेगी कैसे देखिए आपके\r\nलग्न चार्ट में जहां भी चंद्रमा बैठा हो\r\nमैन लीजिए लग्नाचा था आपका और उसमें तीसरी\r\nनंबर राशि में चंद्रमा बैठा था और आपका\r\nलैंड है यह पंच नंबर माली सिंह लग्न की\r\nकुंडली थी तो हमने क्या किया कुंडली को\r\nघुमा दिया और जिस घर में चंद्रमा बैठा है\r\nमून बैठा है उसको हम फ्रंट पर ले आए हमने\r\nएक नंबर मैन लिया इसका मतलब क्या होता है\r\nकी हम यह मैन रहे हैं की अब कुंडली का\r\nराजा चंद्रमा है मून है और मून जहां बैठा\r\nहै उसको हम ginenge घर नंबर एक यह\r\nनंबर कैलकुलेट होंगे\r\nठीक है यह चीज समझ में आई बाकी सॉफ्टवेयर\r\nमैं आपको बनी हुई मिल जाती है नहीं भी\r\nमिलती नहीं भी रोते करना तो क्या करना है\r\nमून जहां बैठा है वहां से ginenge उसको\r\nपहला घर मैन के अब इसके नियम और समझ लीजिए\r\nऔर इस चीज को बहुत ध्यान से समझिए यह सेशन\r\nचंद्र कुंडली का नहीं है ठीक है आज हम जो\r\nडिस्कस कर रहे हैं वो बहुत सीमित दायरे\r\nमें डिस्कशन है की चंद्र कुंडली को कुछ\r\nचीजों के लिए कैसे उसे करना है और जो हम\r\nबताएंगे वो लिमिट नहीं है चंद्र कुंडली की\r\nलेकिन यह आज के हमारे सेशन की लिमिट है\r\nक्योंकि सब चीज एक साथ बता देंगे तो\r\nकन्फ्यूजन हो जाएगा सब कुछ लेके साथ नहीं\r\nचल सकते तो स्पष्ट नियम की यह सीमित दायरा\r\nहै\r\nअब इसमें पहला नियम आपका आएगा मैं बात\r\nकरूंगा चंद्रमा से क्या देखूं चंद्रमा की\r\nस्थिति से क्या देखूं तो आप देखोगे विवाह\r\nके लिए प्लैनेट इन सेकंड एंड सेवंथ हाउस\r\nतो पहला नियम हुआ जिस घर की मुझे बात करनी\r\nहै मैं उसे घर के हाउस लौट की बात नहीं\r\nकरूंगा चंद्र कुंडली में यह आज का लिमिटेड\r\nसेशन है चंद्र कुंडली का पुरी व्याख्या\r\nनहीं है अगर मुझे प्रोफेशन की बात करनी है\r\nतो मुझे क्या देखना है यह सामने कुंडली है\r\nमेरे मैं देखूंगा दसवां घर कहां है ये रहा\r\n10th हाउस चंद्रमा से इस घर में कोई\r\nप्लैनेट बैठा है लेट से मार्स बैठा है और\r\nआपका बिजनेस बैठा है\r\nइन दोनों के संबंध चंद्रमा से कैसे हैं बस\r\nमुझे कोई फर्क नहीं पड़ता की यहां 12 नंबर\r\nराशि है उसका प्लान है जुपिटर है वो कहां\r\nबैठा है कोई फर्क नहीं पड़ता मैं केवल मून\r\nएक प्लैनेट है जो अभी राजा है और उसे राजा\r\nके संदर्भ में दसवें घर में कौन से\r\nप्लैनेट है और उससे मून का क्या संबंध है\r\nबस ये दो चीज मैं जो देखना है ठीक है तो\r\nहम देखेंगे की दूसरे घर में और सातवें घर\r\nमें जो प्लैनेट बैठे हैं उनका चंद्रमा से\r\nक्या संबंध है अगर संबंध अच्छा है राजा से\r\nसंबंध अच्छा है तो दूसरे और सातवें घर के\r\nप्लैनेट की दशा अंतर्दशा विवाह दे सकती है\r\nइसमें कोई प्रॉब्लम नहीं\r\nअब दूसरा नियम समझिए क्या मैं हर जातक के\r\nलिए चंद्र कुंडली उपयोग करूंगा तो जवाब है\r\nआज के सेशन के लिए नहीं वह हम तप करेंगे\r\nजब हम पूर्ण व्याख्या चंद्र कुंडली कर\r\nलेंगे आज का लिमिटेड है इसलिए हम कंडीशन\r\nबता देते हैं की अभी हम लोग किस किस\r\nकंडीशन में चंद्र को दिल्ली को उसे करेंगे\r\nदेखिए अगर आपके हाथ में जो कुंडली आई है\r\nवह कर्क लगने की यानी की कैंसर तो इसके\r\nलिए भी आप चंद्र कुंडली उसे करेंगे क्यों\r\nक्योंकि इसका मलिक चंद्रमा ही होता है तो\r\nइसका मतलब मैं लग्नेश से भी देख रहा हूं\r\nकुंडली एक तो मैं लगने से देखूंगा दूसरा\r\nलग्न का मलिक कौन इसके लिए चंद्रमा है तो\r\nमैं लगने से भी 10वां कर देख रहा हूं\r\nअगर चंद्रमा और लग्नेश एक साथ बैठे हैं तब\r\nभी आप चंद्र कुंडली\r\nजहां बात करेंगे मैरिज का या किसी भी और\r\nचीज का अगर चंद्रमा और लग्नेश किसी कुंडली\r\nमें साथ बैठे हैं तो भी हम चंद्र कुंडली\r\nसे एनालिसिस करके देखेंगे\r\nइससे क्या होगा से चंद्रमा अगर लग्नेश के\r\nसाथ है तो जो घर चंद्रमा से दसवां होगा या\r\nसातवां होगा वो लगने से भी सातवां achchva\r\nहोगा एक ही घर में ही होती है तो फिर\r\nरिलेशन मिलेगा हमको आगे\r\nअगर चंद्रमा लग्न में बैठा हो अब समझने\r\nवाली बात यह है देखिए एक इसे हटा देते हैं\r\nजी\r\nजैसे यह कुंडली में मैंने आपको बताया\r\nचंद्रमा लग्न में है यह लग्न में चंद्रमा\r\nऑलरेडी बैठा हुआ है तो जब मैं इसकी कुंडली\r\nबनाऊंगा चंद्र कुंडली तो यही बनेगी\r\nक्योंकि ये तो ऑलरेडी लगभग है तो फर्क\r\nक्या आएगा फर्क क्या आएगा हमारी नियम नंबर\r\nएक पे जब इस कुंडली को मैं लगने से\r\nदेखूंगा तो मैं देखूंगा इस घर का मलिक\r\nकहां है कौन है कैसी स्थिति में है लेकिन\r\nजब मैं इस घर को देखूंगा चंद्रमा से यानी\r\nकी अब मलिक है चंद्रमा तो चंद्रमा के\r\nचंद्रमा को क्या चाहिए इस घर में कौन से\r\nग्रह बैठे हैं और उससे मेरा संबंध क्या है\r\nतो दोनों अलग-अलग चीज हो जाएंगी आई होप ये\r\nक्लियर होगा ठीक है\r\nएक और इंपॉर्टेंट चीज जिस कुंडली में\r\nचंद्रमा आत्मा कारक हो जाए अब यह मत पूछना\r\nकी आत्मकथा\r\nकी चंद्रमा atmakarak है तो उसके लिए भी\r\nहम चंद्र कुंडली के लिए खोल के देखेंगे\r\nउसका उपयोग करेंगे अब मैन लीजिए आपने\r\nचंद्र कुंडली देखी और यह कांबिनेशन अच्छा\r\nबन रहा है और ये बेनिफिट भी है और मून से\r\nइनके रिलेशन अच्छे भी हैं तो क्या\r\nप्रिडिक्ट कर देंगे प्रिडिक्शन के लिए हम\r\nफिर से नवमांश में भी चेक करेंगे इन दो\r\nप्लैनेट को की क्या यह मैच होते हैं वहां\r\nइनका कुछ संदर्भ है इनका औचित्य है क्यों\r\nक्योंकि हम ढूंढ रहे हैं प्रबल दावेदार एक\r\nस्ट्रांग कांबिनेशन जो जातक को विवाह दे\r\nसके सेटिंग विवाद दे सके तो एक छोटा सा\r\nएग्जांपल देखते हैं पहले इसके बाद आगे\r\nबढ़ेंगे\r\nयह कुंडली अभी शायद लास्ट वीक हमने डिस्कस\r\nकिया था प्रधानमंत्री श्री नरेंद्र मोदी\r\nजी का ठीक है इसमें देखते हैं क्या मैं\r\nउसे कुंडली को आज के हमारे सीमित जो\r\nकैलकुलेशन है chandrakondali का उसके\r\nहिसाब से देख सकता हूं चंद्रमा कहां है\r\nलग्न में तो पहला नियम एक नियम मेरा फॉलो\r\nहोता है दूसरा यह लग्नेश के साथ भी है तो\r\nदो कंडीशन फुलफिल होती है ये चंद्रमा लग्न\r\nमें भी है लग्नेश के साथ है तो जी हान मैं\r\nचंद्रमा से देख सकता हूं इस कुंडली को अब\r\nमुझे बात करनी है प्रोफेशन की तो मत मंगल\r\nसे यानी की मार्च से हमने पहले देख चुके द\r\nइस कुंडली को मैंने देखा मून से दसवां घर\r\nए जाएगा यहां\r\nबैठे हैं विनाश और सैटर्न क्या देखूंगा\r\nमैं मुझे जानना है की इस घर में बैठे ग्रह\r\nक्या राजा के साथ क्योंकि क्योंकि अब इस\r\nकुंडली का मलिक कौन मैन के चलाऊं मैं\r\nचंद्रमा संबंधित कैसा है\r\nमून\r\nवीनस को अपना मित्र बनता है ये हमने देखा\r\nहै और जहां बैठा है उसके हिसाब से यह अति\r\nमित्र हो गए तो चंद्रमा के लिए शुक्र हो\r\nगया अति मित्र और चंद्रमा के लिए शनि हो\r\nगया मित्र क्योंकि न्यूट्रल है और\r\nतात्कालिक में यह मित्र बन जाता है तो\r\nदोनों एक आपका बेस्ट फ्रेंड है और एक\r\nफ्रेंड है और यही रीजन था की वो पहली बार\r\nमुख्यमंत्री बनते हैं वीनस से सैटिन की\r\nस्टेज में जबकि पहले\r\nचैप्टर\r\nए जाएगा तो वह कैसे कैलकुलेट किया कैसे\r\nकांबिनेशन बना की उन्हें यह पोस्ट मिल गई\r\nतो अभी समझ में आया की इस कुंडली में\r\nचंद्रमा का इंपॉर्टेंस है चंद्रमा के\r\nरिलेशन से यह दोनों ग्रह दसवें घर में\r\nबैठकर बेनिफिट कम कर रहे हैं स्पष्ट\r\nहै इसी कारण जिसने ये कुंडली देखी उसको यह\r\nसमझ आया की ये जब ये हुआ कैलकुलेशन तो ये\r\nकब हुआ\r\nइस दौरान और ये दोनों चंद्रमा के लिए\r\nबेनिफिट है यानी की यह कुंडली सबसे\r\nमहत्वपूर्ण है चंद्रमा के हिसाब से इसीलिए\r\nजब मून का पीरियड आया तो उन्हें मोती\r\nपहनने की सलाह दी गई पाल पहना उन्होंने\r\nइसीलिए यहां चंद्रमा 8 डिग्री का है उसकी\r\nमजबूती बनाने के लिए और क्योंकि\r\nयोग चल रहा है आपका इसमें जो हमने पहले\r\nडिस्कस किया था याद है ना आप लोगों को\r\nएक और क्वेश्चन था की मंगल को स्ट्रांग\r\nक्यों नहीं किया मंगल तो लग्न है\r\nलेकिन अभी जैसा हमने देखा की हमने अब यह\r\nमाना की क्या चंद्रमा को राजा मैन के\r\nकुंडली कम कर रही है बिल्कुल कर रही है\r\nजैसे ही चंद्रमा को राजा माना वीनस सैटर्न\r\nबेनिफिट हो गए और उन्होंने अपनी दशा\r\nअंतर्दशा में मुख्यमंत्री बनवा दिया तो\r\nमैं फिर क्यों मंगल को स्ट्रांग करूंगा और\r\nएक दूसरा कारण ये भी है ये चंद्र मंगल योग\r\nभी बनाते हैं और चंद्र मंगल योग आपने पढ़ा\r\nहै और कौन चाहेगा की उसकी कुंडली में लग्न\r\nमें चंद्र मंगल योग बहुत स्ट्रांग हो जाए\r\nऔर इसी कारण है की मंगल के लिए भी रतन\r\nधारण नहीं किया गया तो ये हमने प्रोफेशन\r\nके संदर्भ में समझा की चंद्रमा से कुंडली\r\nकैसे प्रभावित होती है लेकिन अभी केवल चार\r\nचीज है की चंद्रमा की स्थिति कहां है\r\nजिसके हिसाब से हमने सिखा है क्योंकि पूरा\r\nअध्ययन अभी नहीं कर रहे आगे बढ़कर देखेंगे\r\nअभी अच्छा क्वेश्चन है क्या राहु और केतु\r\nमैरिज दे सकते\r\nहैं दोनों अब दोनों को मैंने एक साथ क्यों\r\nबोला क्योंकि जो ग्रह राहु के साथ होगा\r\nउसे केतु एस्पेक्ट करेगा और जिसकी युति\r\nकेतु के साथ होगी उसको राहु एस्पेक्ट\r\nकरेगा क्योंकि सेवंथ बैठते हैं दूसरे से\r\nक्लियर है चलिए\r\nयह हम सब जानते हैं हमने हजारों बार\r\nसैकड़ो बार यह पड़ा है की राहु और केतु अब\r\nकैसे परिणाम देंगे जिस राशि में है उसके\r\nअनुसार देंगे जिस व्यक्ति में उसके अनुसार\r\nदेंगे और एस्पेक्ट के अनुसार रिजल्ट देंगे\r\nलेकिन इसका मतलब क्या फॉर एग्जांपल मैन\r\nलीजिए एक राहु आपका सैटर्न सन के साथ बैठा\r\nहुआ है और केतु आपका वीनस के साथ बैठा हुआ\r\nहै तो इसका मतलब क्या है की राहु सूरज हो\r\nजाएगा\r\nया राहुल सूर्य के घर यानी की पांचवी राशि\r\nका जो हाउस है उसका रिजल्ट देने लगेगा\r\nकैसे रिजल्ट देगा यह लाइन तो ठीक है लेकिन\r\nकहां से आएंगे समझी\r\nराहु अगर सूर्य के साथ है तो वह सूर्य के\r\nहाउस को टच नहीं करेगा सूर्य का स्वाभाविक\r\nनेचर क्या है वो ले लेगा और कुंडली में\r\nअगर सूर्य को कोई विशेष स्थान मिला है तो\r\nउसके रिजल्ट भी देगा से कम केतु करेगा अगर\r\nसूरज किसी कुंडली में डीके है समझ गए डीके\r\nतो जी हान राहु मैरिज कर देगा सेन केतु के\r\nलिए अप्लाई होता है अगर वीनस किसी को डील\r\nमें दिखे है और केतु उसके साथ कहीं\r\nजॉइनिंग है तो केतु उसके स्वभाव लेगा कहते\r\nहैं केतु प्लैनेट है डिटैचमेंट का लेकिन\r\nएग्जांपल देखेंगे जहां केतु ने मैरिज कराई\r\nराहु को बोला जाता है mellife है लेकिन\r\nहमने पिछले एग्जांपल में देखा की राहु\r\nप्राइम मिनिस्टर भी बनवा सकता है तो\r\nइंडिपेंडेंस की ग्रह कहां बैठा है जिसके\r\nसाथ बैठा है उसका नेचुरल गुड क्या है और\r\nएक और महत्वपूर्ण चीज जब हम मैरिज\r\nप्रिडिक्शन कर रहे हैं तो उसे समय की बात\r\nकरेंगे या हम बात करेंगे\r\nयह आपका सातवां घर\r\nक्या ऐसे लोग हैं जो 25 26 27 साल की उम्र\r\nमें जिनकी मृत्यु हो जाती है अब उसी टाइम\r\nपर मैन लीजिए आप दूसरे और सातवें के\r\nकांबिनेशन से मैरिज प्रिडिक्शन कर रहे हो\r\nऔर उसी समय आदमी की मृत्यु हो जाए फिर तो\r\nयह कैसे कैलकुलेट होगा इसीलिए 9 मार्च में\r\nआप हर चीज को चेक करते हो तो अगर हमने कहा\r\nकी राहु इसके साथ दारा कारक के साथ है कर\r\nदेगा मैरिज तो इसका मतलब यह नहीं है की बस\r\nलगना चार्ट में देखा और हो जाएगा नहीं\r\nमुझे हर चीज 9 मार्च के साथ चेक करनी है\r\nकन्फर्मेशन लेना है और अगर चंद्र कुंडली\r\nमें बन रहा है तो उसका कन्फर्मेशन भी नमन\r\nसे लेना है और 9 मार्च में कोई चीज बन रही\r\nहै तो लग्न को कंफर्म करना है तब जाके एक\r\nबेस्ट पॉसिबल सती टाइम निकलकर आएगा जहां\r\nआपको सेटिस्फेक्शन होगा तो अब भी एक\r\nएग्जांपल लेते हैं एनालिसिस"},{"topic":"चंद्र - योग - जानिए कुंडली में बनने वाले महत्वपूर्ण योग - Important Yoga in Kundali-","text":"गुड मॉर्निंग क्लास तो आज हम बात करेंगे\r\nकुछ इंपॉर्टेंट योग जो कुंडली में बनते\r\nहैं और रिलेटेड तू मून मतलब चंद्रमा से\r\nबनने वाले\r\nजो हम देख लेते हैं\r\nदेखिए पहला योग है\r\nजब चंद्रमा से द्वितीया भाव में कोई ग्रह\r\nहो और द्वादश यानी की 12वें भाव में कोई\r\nग्रह ना हो तो उनका योग बनता है एग्जांपल\r\nयहां पर आप देखेंगे तीसरे घर में यहां पर\r\nआपको मून दिखाई देगा और उससे दूसरा घर\r\nजाने की 4000 में आपको मंगल दिखाई देगा तो\r\nयह और मैं यहां पर कोई ग्रह नहीं है कोई\r\nप्लैनेट नहीं है तो इसका मतलब यह कहलाएगा\r\nअब इसके लिए विशेष चीज याद रखना है जितने\r\nभी हम यहां पर योग पढ़ेंगे उनके लिए\r\nचंद्रमा का होना जरूरी है और साथ में वो\r\nएप्लीकेबल है मंगल के लिए बुद्ध के लिए\r\nगुरु के लिए शुक्र के लिए और शनि के लिए\r\nयानी सूर्य को इसमें इंवॉल्व नहीं किया\r\nगया तो इन पंच प्लैनेट से बनेंगे ये सारी\r\nके सारी लोग चंद्रमा के साथ में\r\nतो सनफ्लावर को क्लियर है की किसी घर में\r\nचंद्रमा है और उसके अगले घर में कोई भी\r\nदूसरा ग्रह हो इन पांचो में से और 12 घर\r\nमें कोई भी ग्रह ना हो तो सनफा योग बनेगा\r\nतो ऐसे जातक जो sunfo योग में जन्म हुआ है\r\nवो क्या क्या होगा उनके पास या तो वो राजा\r\nया उसके समानी वर्चस व्यय अधिकार वालों को\r\nहोंगे साथ में बहुत विद्वान इंटेलिजेंट\r\nबुद्धिमान होंगे\r\nवेल्डिंग होंगे धनवान होंगे और बहुत\r\nप्रसिद्ध होंगे और साथ में उनके पास खुद\r\nकी कमाई हुई बहुत अधिक संपत्ति होगी अब\r\nक्योंकि ऐसे योग आपको कई जगह मिलेंगे तो\r\nवीडियो के लास्ट में हम समझेंगे की लोगों\r\nको देखना कैसे फलित करना है कुछ नहीं है\r\nमैं उसके तो उसके बारे में चर्चा करेंगे\r\nअगला योग देखते हैं\r\nहमारे उनको कंसीडर करने वाले\r\nहैं तो जब मून से 12 में कोई ग्रह हो मतलब\r\nचंद्रमा से\r\nग्रह हो और दूसरे ग्रह\r\nउसका जस्ट अपोजिट एग्जांपल देख लेते हैं\r\nदेखिए एग्जांपल में फिफ्थ हाउस आपको यहां\r\nदिख रहा होगा यहां पर मून है\r\nहै और इसका बार-बार घर होगा 4th हाउस जब\r\nयहां से 12 घर काउंट करेंगे तो वहां पर\r\nजुपिटर यानी की गुरु और चंद्रमा से दूसरे\r\nघर में कोई ग्रह नहीं है मतलब चंद्रमा से\r\nदूसरे घर में कोई ग्रह नहीं होना चाहिए और\r\nउससे पहले यानी की 12वीं घर में कोई भी इन\r\nपांचो में से कोई ग्रह हो तो वो कहलाता है\r\nunfayog\r\nऐसे जन्म योग में जन्मे जो जातक है वो\r\nदिखने में बहुत सुंदर अट्रैक्टिव होते हैं\r\nबीमारियों से मुक्त उनका शरीर होता है\r\nसमाज में उन्हें और सारे भौतिक सुखों का\r\nयोग में जन्म लेने वाले जातकों के पास यह\r\nसारी चीज उपलब्ध होती हैं\r\nयह दो धारा\r\nतो जब चंद्रमा से दूसरे भाव में भी कोई\r\nग्रह हो सेकंड हाउस में भी प्लैनेट हो और\r\n12th हाउस में भी प्लानिंग हो याने की\r\nचंद्रमा के आगे और पीछे दोनों ही जगह इन\r\nपांचो ग्रह में से कोई भी प्लैनेट हो\r\nसूर्य को छोड़कर तो दुर्धरा योग बनता है\r\nफॉर एग्जांपल देख लेते हैं फर्स्ट हाउस\r\nमें आपका मूड है तो देखिए सेकंड हाउस मतलब\r\nकी सेकंड उसके बाद वाला जो घर है दूसरा घर\r\nउसमें सैटर्न है और बार-बार जो जुपिटर है\r\nतो इस तरह से चंद्रमा के आगे और पीछे\r\nदोनों तरफ ग्रह है इन पांचो में से तो ऐसे\r\nयोग को दोनों धारा योग कहते हैं तो ऐसे\r\nयोग में जन्म लेने वाले जातकों के पास\r\nसंपन्नता होगी धनवान होंगे\r\nबहुत सारी व्हीकल गाड़ियां हो सकती हैं\r\nदानिश स्वभाव से होगा व्यक्ति और मटेरियल\r\nकंप्रेसर की भौतिक सुविधाओं की कमी नहीं\r\nहोगी क्योंकि हमें फलित करना है जब लोगों\r\nको तो इसके बारे में हम आगे चर्चा करेंगे\r\nजब चंद्रमा से प्रथम यानी की उसी घर में\r\nदूसरे और 12 घर में यानी 12th और सेकंड\r\nहाउस\r\nएग्जांपल से सीधे समझते हैं देखेंगे\r\nकोई ग्रह नहीं होना चाहिए और चंद्रमा के\r\nबाद यानी की उससे सेकंड हाउस में कोई घर\r\nनहीं होना चाहिए तो ऐसे स्थिति में बनता\r\nहै जिसे अच्छा नहीं माना जाता तो ऐसे जाता\r\nहै\r\nafflected बाय पावर्टी एंड ट्रबल गरीबी और\r\nपरेशानियों से युक्त रहता है पूरा जीवन\r\nपुरी लाइफ\r\nहोती है या बुरी होती है\r\nस्पेशली इसको साइनिफिकेंस दिया की केंद्र\r\nमें योग्यता विचार जो है मुख्यतः ऐसे\r\nलोगों के लिए करना चाहिए जिनका जन्म शाही\r\nपरिवार तो आज के समय में शाही परिवार का\r\nअर्थ है बहुत उच्च लेवल के परिवार या फिर\r\nसंपन्न परिवार उनकी कुंडली में ऐसा योग\r\nहोने से वह फलित ज्यादा बेहतर होता है एक\r\nसामान्य व्यक्ति की तुलना में तो आगे\r\nअगला बस्ता हमारे पास चंद्र मंगल योग तो\r\nबहुत सिंपल से योग है यह तुझे आपके कुंडली\r\nमें किसी भी घर में किसी भी राशि में\r\nचंद्रमा और मंगल युति हो जाए साथ में बैठ\r\nजाए तो चंद्रमा मंगल होगा जैसे फॉरेन\r\nएग्जांपल हम यहां देख सकते हैं हमारे 7000\r\nमें यहां पे मंगल और चंद्रमा एक साथ बैठे\r\nहुए हैं ठीक है तो ऐसे जातक इनका जो\r\nअर्निंग का सोर्स होगा वो unscrib प्लस\r\nमिंस होगा मतलब की जो अच्छे नहीं माने\r\nजाते दूसरा यह बुद्धिमान होंगे भौतिक\r\nसक्सेसफुल उनको मिल जाएगी लेकिन\r\nइन योग में जातक जो होगा वो अपनी मैन के\r\nसाथ या दूसरी औरतों के साथ जो व्यवहार\r\nकरेगा वो नारी ट्रीट करेगा बहुत खराब\r\nस्थिति से करेगा और यही इस योग की सबसे\r\nबड़ी कमजोरी मणि जाती है जो की आज मिंस भी\r\nखराब माना जाता था लेकिन अगर आज के समय की\r\nबात करें तो आज हम unscrup प्लस मिंस आप\r\nपढ़ सकते नीचे की आज के डेट में शराब के\r\nठेके हुए रिश्वत का पैसा हुआ है सत्ता हुआ\r\nइन चीजों को आज के समय\r\nजाता है जो की पुराने समय में ये चीज बहुत\r\nही\r\nलेवल की मणि जाती थी इसलिए इनको निष्क\r\nप्लस माना गया पर आज के समय में बहुत\r\nनॉर्मल लोग हैं बस एक इफेक्ट जो यहां पे\r\nबुरा जाता है वो ये है की महिलाओं के\r\nप्रति या इनका व्यवहार जो है मैन के प्रति\r\nबहुत खराब रहता है\r\nयह चार-पांच लोग द छोटे-छोटे जो हमने समझे\r\nउनके एग्जांपल देखें अभी कुछ बेसिक नियम\r\nहै की लोगों को फलित कैसे करना है तो सबसे\r\nपहले चीज समझ लीजिए\r\nयदि किसी कुंडली में लगने यानी लग्न का जो\r\nमलिक है वो कमजोर है वीक है तो किसी भी\r\nशुभ योग का परिणाम पूरा नहीं मिलेगा ये\r\nसिंपल सा नियम है हर चीज के लिए अप्लाई\r\nहोता है तो अगर राजा ही कमजोर है तो फिर\r\nकोई बेनिफिट नहीं मिलेगा उसे अगला\r\nजिस किसी योग को जो ग्रह बना रहे हैं उन\r\nग्रहों का ताकतवर स्ट्रांग होना जरूरी है\r\nअगर ग्रह मृत है अस्त है या बलवान नहीं है\r\nअंश बाल नहीं है तो वह प्रभाव दे ही नहीं\r\nपाएगा तो किसी भी योग का बुरा या अच्छा सर\r\nनहीं मिलेगा आखिरी\r\nशुभ योग अगर बनता है तो उसके लिए सबसे\r\nपहले आप कंसीडर करेंगे की जिस जातक के\r\nआपको मिली देख रहे हैं उसमें योग बनाने\r\nवाले ग्रह आपके ग्रह या शुभ ग्रह\r\nहैं यानी की मलेफिक प्लैनेट्स है तो वो\r\nशुभ योग बनने के बाद भी रिजल्ट नहीं दे\r\nपाएंगे तो यह दो-तीन गाइडलाइन है जिससे\r\nउसे करना चाहिए फलन कथन करने से पहले\r\nAll\r\nFrom the series"},{"topic":"दिगबली गृह देता है करियर में सफलता -षडबल रहस्य- ज्योतिष शोध- Planetary Strength- A Research","text":"गुड मॉर्निंग\r\nचलिए टबल का मतलब है छ तरह के बल यानी कि\r\nसिक्स फोल्ड स्ट्रेंथ लेकिन आज हम पूरे शट\r\nबल यानी छ बल की बात नहीं करेंगे किसी एक\r\nबल की जो बहुत इंपॉर्टेंट है उसकी बात\r\nकरेंगे जिसे हम कहते हैं दिग बल\r\nडायरेक्शनल स्ट्रेंथ क्या होता है कैसे\r\nनिकालते हैं अभी एक्सप्लेन कर दूंगा कुछ\r\nचीज उससे पहले बेसिक समझ लीजिए\r\nदिग बल दिग बली प्लानेट का यूज करके कोई\r\nभी व्यक्ति अपने करियर में या अपनी लाइफ\r\nमें कुछ बेटर चीज हासिल कर सकता है दूसरी\r\nचीज यह है कि आपने जो कांसेप्ट पढ़े हैं\r\nकि अगर थ हाउस का लॉर्ड किसी हाउस में है\r\nमान लीजिए तीसरे घर में है तो व्यक्ति\r\nतीसरे घर से संबंधित काम कर सकता है जब आप\r\nइसकी एकसी चेक करेंगे इस नियम की इस तथ की\r\nतो लगभग 25 से 30 पर आती है इसी संदर्भ\r\nमें हमने करीब 200 कुंडलियों के ऊपर डबल\r\nको लेकर कुछ रिसर्च किया है उसमें से एक\r\nचीज आज आपके साथ मैं शेयर कर रहा हूं कोई\r\nभी व्यक्ति चाहे एस्ट्रोलॉजी ज्योतिष आता\r\nहै नहीं आता है इससे कोई फर्क नहीं पड़ता\r\n10 से 20 सेकंड में यह देख सकता है कि\r\nउसकी कुंडली में कौन से ग्रह दिग बली है\r\nजिनका उपयोग वो लाइफ को बेटर कर करने के\r\nलिए कर सकता है इसके बाद में कुछ एग्जांपल\r\nहम लोग देखने वाले हैं और फिर फाइनली एक\r\nडिस्कशन करेंगे ठीक है तो जल्दी से मैं\r\nआपको पहले बल बता देता हूं सारे डिस्कस आज\r\nनहीं करेंगे पहला है शड बल में पहला बल है\r\nस्थान बल जिसे पोजीशनल स्ट्रेंथ कहा जाता\r\nहै दूसरा है काल बल जो टेंपोरल स्ट्रेंथ\r\nके नाम से जाना जाता है तीसरा है दिग बल\r\nडायरेक्शनल यानी कि दिशा बल इसकी आज हम\r\nचर्चा करने वाले हैं फिर है चेष्टा बल जो\r\nमोशन के हिसाब से स्ट्रेंथ निकालता है\r\nयानी कि वक्री जब ग्रह होते हैं उसके\r\nबेसिस पर कैलकुलेशन होता है फिर है दग बल\r\nजो दृष्टि सिद्धांत पर आधारित है और\r\nनैसर्गिक बल मतलब की हर ग्रह का अपना एक\r\nपरमानेंट स्ट्रेंथ होता है आप जोय शुरू\r\nमें नंबर्स देख रहे हो इसका मतलब यह है कि\r\nमुझे अगर स्थान बल निकालना है तो मुझे\r\nपांच अलग-अलग बल को जोड़ना पड़ेगा मुझे\r\nअगर काल बल निकालना है तो मुझे नौ अलग-अलग\r\nबल को जोड़ना पड़ेगा तो कैलकुलेशन लंबे हो\r\nजाते हैं लेकिन जो आज हम बात कर रहे हैं\r\nवो है डायरेक्शनल स्ट्रेंथ दिग बल जिसमें\r\nबहुत कैलकुलेशन नहीं चाहिए और केवल कुंडली\r\nदेख के भी आप बता सकते हैं कि कौन से ग्रह\r\nदिग बली है\r\nचलिए कैसे निकालते हैं कैसे देख पाएंगे वो\r\nसमझ लीजिए 10 से 20 सेकंड आपको फिर\r\nनिकालने में देखने में लगेगा चाहे कोई भी\r\nकुंडली हो किसी व्यक्ति की कुंडली हो यह\r\nसबके लिए सेम है पहला भाव यानी कि यह घर\r\nपहला भाव फर्स्ट हाउस यहां पर दिशा है\r\nपूर्व यानी कि ईस्ट डायरेक्शन सातवा घर\r\nयानी कि सेवंथ हाउस यहां पर डायरेक्शन\r\nयानी कि दिशा है पश्चिम दिशा वेस्ट\r\nडायरेक्शन उसी तरह थ हाउस दसवा भाव यह है\r\nसाउथ डायरेक्शन यानी कि दक्षिण दिशा और\r\nफोर्थ हाउस यानी कि उत्तर दिशा डायरेक्शन\r\nये हर कुंडली के लिए फिक्स है यही\r\nडायरेक्शन होंगे हर कुंडली में हर चार्ट\r\nमें हर होरोस्कोप में ठीक है अब केवल इतना\r\nदेखना है कि कौन से ग्रह किस डायरेक्शन\r\nमें किस हाउस में दिगली हो जाते हैं फरन\r\nसूर्य और मंगल सन एंड मार्स कुंडली के\r\nदसवें घर में दिग्बी कहलाते हैं यानी कि\r\nसाउथ डायरेक्शन में पूरी तरह से दिग्बी\r\nहोते हैं शनि सैटन कुंडली के सातवे घर\r\nयानी कि सेवंथ हाउस में दिग बली कहलाता है\r\nऔर वीनस और मून चंद्रमा और शुक्र कुंडली\r\nके फोर्थ हाउस यानी कि चौथे भाव में\r\nदिग्बी होते हैं तो बड़े आसानी से हम ये\r\nबता सकते हैं कि पूरी तरह दिगबरा\r\nजब गुरु या बुध जुपिटर मरकरी फर्स्ट हाउस\r\nमें हो पहले भाव में हो सूर्य और मंगल दसव\r\nभाव में सन एंड मार्स इन थ हाउस सेटन इन\r\nसेव हाउस शनि सातवे भाव में दिग बली होता\r\nहै पूरी तरह से और चंद्रमा और शुक्र वीनस\r\nएंड मून कुंडली के चौथे भाव में पूरी तरह\r\nसे दिगली होते हैं लेकिन पोजीशन यह भी हो\r\nसकती है कि सूर्य यहां ना होके यहां हो\r\nपहले में हो दूसरे में हो सातवे में हो\r\nबवे में हो नौवे में हो तो क्या दिबल पूरा\r\nखत्म हो जाएगा या कितना दिगल रहेगा और मैं\r\nउसको दिगली मानूंगा या नहीं बहुत आसान सा\r\nसिद्धांत बता रहा हूं बहुत कैलकुलेशन करने\r\nही नहीं है कोई भी कुंडली उठाइए फॉर एन\r\nएग्जांपल सूर्य का एग्जांपल ले लेता हूं\r\nएक दूसरा ले लूंगा आपको सूर्य दिखता है\r\nदसवें घर में इसका मतलब वो 100% बली हो\r\nजाता है\r\nआप जब एक्चुअल में देखेंगे तो हो सकता है\r\nआपको 92 मिले 94 मिले 98 मिले लेकिन आप\r\nउसको पूरी तरह से दिग बली मान सकते\r\nहैं जैसे जैसे सूर्य हाउस चेंज करेगा यहां\r\nयहां यहां यहां अगर कुंडली के ऐसे अलग अलग\r\nभाव में है तो आपको क्या करना है जिस हाउस\r\nमें य दिगली है उससे अगर दूसरे भाव में है\r\nतो आप 14 प्र यानी कि 14 पर माइनस कर\r\nदेंगे इसका मतलब है कि अगर यहां सूर्य\r\n100% 100% दिग बली माना जाता है तो इस घर\r\nमें 14 पर कम कर दो यानी कि 86 पर दिगभ\r\nहोगा और उसी तरह अगर तीसरे घर में चला\r\nजाता है तो 14 और 14 28 यानी कि 14 प् 14\r\n28 पर कम कर दो तो 72 पर की वैल्यू रह\r\nजाती है पर का दिग बल रह जाता है उसी तरह\r\nसे सूर्य जब घूमता हुआ यहां आ जाएगा इसका\r\nमतलब सूर्य का दिग बल जीरो हो जाएगा\r\nवास्तव में जीरो नहीं होता तो कभी पाच का\r\nदिखेगा कभी सात का कभी न का कभी 10 का\r\nमुझे इससे कोई फर्क नहीं पड़ता अगर\r\nप्लानेट का दिग बल 75 पर से ऊपर है 75 प्र\r\nसे ऊपर है इसका मतलब सूर्य और मंगल अगर इस\r\nघर में है इस घर में है या पीछे वाले घर\r\nमें है अपने घर से अपने पूर्ण दिगबरा\r\nसूर्य और मंगल एक घर आगे या एक घर पीछे है\r\nतो केवल 14 पर यानी कि 14 पर का लॉस होगा\r\nवो लगभग 85 86 पर दिबल होंगे जिसे मैं\r\nमान्य करूंगा दिगल कहूंगा उसी तरह मान\r\nलीजिए जुपिटर है फर्स्ट हाउस में पहले भाव\r\nमें दिग बली होता है तो मैं इसको सेकंड\r\nहाउस और थ हाउस पहले भाव और केवल बवे भाव\r\nमें दिग बली मानूंगा तो आप डायरेक्शन से\r\nभी समझ सकते हैं क्योंकि डायरेक्शन ईस्ट\r\nहै तो ईस्ट के आसपास की जो डायरेक्शन है\r\nयहां यह दिग बली कहलाएगा जुपिटर सूर्य\r\nमंगल दक्षिण दिशा के आसपास के लोकेशन पर\r\nदिग बली कहलाएंगे तो कैलकुलेशन की जरूरत\r\nनहीं है सूर्य मंगल अपने थ हाउस से एक\r\nहाउस पीछे या आगे हो दिली हो जाएंगे सेकंड\r\nशनि अपने सेवंथ हाउस पूर्ण दिगली हाउस से\r\nअगर छ और आठवे हाउस में है यानी कि एक घर\r\nपहले एक घर बाद में भी हो तो ये तीनों\r\nहाउस में सेकंड दिगल होगा लेकिन सेवंथ\r\nहाउस में पूरी तरह से दिगल होगा तो मैं एक\r\nहाउस और आगे और एक हाउस पीछे को दिग बली\r\nके कैटेगरी में डालूंगा मैं मानूंगा कि ये\r\nदिग बली है इतना सा आसान सा कैलकुलेशन है\r\nकोई भी कुंडली में कोई भी ग्रह कहां बैठे\r\nया आसानी से देख सकते हैं कुछ परसेंटेज का\r\nफर्क आ सकता है मैं आपको बता देता हूं\r\nआपको कुंडली में सूर्य दिखता है यहां आपने\r\nमान लिया दिग बली है मान लीजिए डिग्री है\r\n2 डिग्री भाव की डिग्री है 2 डिग्री लेकिन\r\nसूर्य की डिग्री है 25 डिग्री तो बेसिकली\r\nसूर्य यहां दिखेगा और इस वजह से इसका दिग\r\nबल बहुत कम हो जाएगा तो कुछ चार्ट में ये\r\nचीज देखने को मिल सकती है उसका ध्यान रख\r\nलीजिए ठीक है चलिए कुछ एग्जांपल प जाते\r\nहैं क्योंकि जो डेफिनेशन पढ़ी है कि 10 लड\r\nदूसरे में हो तो फादर का बिजनेस में चला\r\nजाएगा थर्ड में हो तो थड हा उस के काम\r\nकरवा दो सेव में हो इस तरह की चीज हमने\r\nपढ़ी है और उसी के संदर्भ में जो दो चा दो\r\nकुंडलियों पर हमने जो शोध की है उसके बारे\r\nमें कुछ नतीजे निकले वो आपको शेयर कर देता\r\nहूं पहले चार्ट पर आते हैं दवे घर का लड\r\nहै मरकरी बुध और कुंडली के दूसरे घर में\r\nबैठा है अब मैं देखता हूं क्या मरकरी दिग\r\nबली है यहां पर मरकरी का जो वैल्यू बुध का\r\nजो दिगल निकल के आया है वह है 91 पर 91\r\nप्र और रूपा में जब मैं बात करता हूं तो\r\nबेसिकली एक रूपा का मतलब होता है 60 सि\r\nअंशा 60 में से 54 पॉइंट इसको मिले हैं\r\nइसलिए मैं आपको रूपा प नहीं जा रहा\r\nक्योंकि कैलकुलेशन टिपिकल हो जाते\r\nपरसेंटेज के हिसाब से जाएंगे तो मरकरी\r\nयानी कि बुध यहां से सेकंड हाउस में है 14\r\nपर कम होना चाहिए यानी कि लगभग 86 होना\r\nचाहिए य उससे ज्यादा क्यों होगा क्योंकि\r\nइस भाव के मध्य से ये थोड़ा सा पहले होगा\r\nयानी कि फर्स्ट हाउस के पास में होगा\r\nइसलिए ये आपको 85 ना दिखा के 91 है 91 है\r\nलेकिन मुझे फर्क नहीं पड़ता मरकरी बुध\r\nयहां यहां यहां मेरे लिए एक बली का काम\r\nकरेगा तो क्या इस जातक को थ हाउस के लॉजिक\r\nसे सेकंड हाउस रिलेटेड काम करना चाहिए चाट\r\nहै स्वामी विवेकानंद जी का और हम सब जानते\r\nहैं उनका पूरा वर्क पूरा जो भी उनको हासिल\r\nहुआ है गौरव सम्मान प्रतिष्ठा सब केवल और\r\nकेवल उनके वाणी के काम से हुआ है करियर\r\nअसेसमेंट की बात में नहीं कर रहा दिग बली\r\nग्रह का खुद यूज मरकरी कारक है\r\nकम्युनिकेशन का वाड़ी का भी कारक है\r\nराइटिंग का कारक है लिटरेचर का कारक है और\r\nक्योंकि सेकंड हाउस है आपका वाणी का\r\nऔर देखेंगे नस के साथ में भी है ठीक है\r\nअभी मैं कॉम्प्लिकेट नहीं कर रहा जिस\r\nचार्ट में थ हाउस का लबली होक किसी दूसरे\r\nहाउस में है क्या जातक के करियर में उस\r\nभाव का महत्व बढ़ जाता है बिल्कुल है वहा\r\nके रिजल्ट आपको दिख रहे और एपल आपको\r\nदिखाता हू लाइन\r\nसे दूसरे चार्ट आते हैं\r\nचार्ट थ हाउस का लड चंद्रमा खुद दसव घर\r\nमें है चंद्रमा मून य दिग बली नहीं होता\r\nचौथे घर में दिगली होता है यानी यहां पर\r\nदिग बल बिल्कुल खत्म हो गया जीरो हो गया\r\nयानी की छ सा आ 10 के आसपास कुछ आपको\r\nमिलेगा यानी कि क्या नेटिव दसवे घर का काम\r\nकरें अब इस चार्ट में मैंने देखा की सबसे\r\nदिगली प्लानेट कौन सा है अगेन मरकरी यानी\r\nकि बुध मुझे सबसे स्ट्रंग प्लानेट दिखाई\r\nदेता है जो कुंडली के पहले भाव में है\r\nइंडिपेंडेंट वर्क खुद के स्किल्स के साथ\r\nपहला भाव साइन कौन सा है सात नंबर साइन\r\nपता है साइन है सोशल जस्टिस का साइन है\r\nलीगल सिस्टम का ये सारी चीजों का लेकिन\r\nअभी फिर मैं करियर पर नहीं जा रहा चार्ट\r\nहै महात्मा गांधी का ठीक है इन्होंने क्या\r\nलगता है आपको करियर में कि बेसिकली इनका\r\nकरियर मून से संबंधित है या वास्तव में\r\nइनके करियर में मरकरी और फर्स्ट हाउस का\r\nविशेष योगदान और उसके साथ सातवें नंबर\r\nसाइन का योगदान देखने को मिलता है यानी कि\r\nहाउस का ल थ हाउस में है तो क्या यह\r\nकांसेप्ट अप्लाई होता\r\nहै नेक्स्ट एग्जांपल पर आ जाते\r\nहैं थ का लड सूर्य है 2 का टबल है यानी कि\r\nटबल सॉरी दिग बल नहीं है सूर्य कहा दिगली\r\nहै यहां यहां यहां तो दसव घर का लड के पास\r\nदिगल नहीं है दिगली प्लानेट कौन से है बुध\r\nहै गुरु है मरकरी है जुपिटर है य एक\r\nकांसेप्ट और याद रखिए जुपिटर सूर्य के साथ\r\nयहां पूरी तरह से कॉमस है जब मैं ज्योतिष\r\nका कोई एक कांसेप्ट पढ़ता हूं तो इसका\r\nमतलब ये नहीं कि दूसरा भूल जाऊ कि अस्त\r\nग्रह है यहां पूरी तरह से अस्त है इसका\r\nमतलब मेरे लिए मेन कारक है मरकरी जुपिटर\r\nथोड़ा हेल्प कर देगा चाट है अटल बिहारी\r\nवाजपेई का सेकंड हाउस वाणी का कारक है\r\nमरकरी राइटिंग का कारक है और हम सब जानते\r\nहैं कि ये बिल्कुल प्रधानमंत्री रहे हैं\r\nलेकिन ये जाने किस चीज के लिए जाते हैं एक\r\nकुशल वक्ता होना अपनी पोएट्री के लिए\r\nकाव्यों के लिए अपने राइटिंग वर्स के लिए\r\nजाने जाते हैं तो क्या दिग बली\r\nप्लानेट की वजह से यह हो रहा है या थ\r\nलॉर्ड की वजह से हो रहा है थ लॉड अगर\r\nदिगबरा वाइज मैं दूसरे\r\nदिगबरा के किसी एक पहलू को बेहतर बनाने के\r\nलिए कर सकता हूं अगले चा जाते हैं ये\r\nचार्ट है हा एक फिल्म स्टार है बॉलीवुड\r\nसेलिब्रिटी है फिल्म स्टार फिल्म एक्टर है\r\nआप देखेंगे अगेन सिंह लगन सिंह राशि है\r\nयहां पर सूर्य सेकंड हाउस में बैठा हुआ है\r\nदिग बली हो नहीं सकता क्या इस व्यक्ति को\r\nसेकंड हाउस के काम मिले हुए हैं नहीं यह\r\nवीनस देखोगे आप शुक्र सबसे दिगबरा\r\nमें बैठा हुआ है हाउस ऑफ कम्युनिकेशन थर्ड\r\nहाउस में है यानी कि थ हाउस का लर्ड का\r\nसेकंड हाउस में होना कोई फर्क नहीं देता\r\nक्योंकि दिग बली नहीं है लेकिन चार्ट का\r\nकुंडली का सबसे दिग बली प्लानेट शुक्र है\r\nजिसने करियर में वीनस का यानी कि बॉलीवुड\r\nमीडिया इंडस्ट्री में पहचान बड़े लेवल पर\r\nदिलवाई है तो\r\nअगेन दिग बली वो प्लानेट है जिससे ना केवल\r\nआप उसको बैलेंसिंग करने का काम कर सकते\r\nहैं दिग बली वो प्लानेट है जिसका आप अपनी\r\nलाइफ में या अपने नेटिव की लाइफ में यूज\r\nकर सकते हैं और यह बहुत सारी कुंडली पर\r\nहमने अप्लाई करके देखा है इसके बहुत बेहतर\r\nरिजल्ट आपको देखने को मिलेंगे अगले चार्ट\r\nप आ जाते हैं चार्ट है बिल गेट्स का अगेन\r\nसूर्य सॉरी जुपिटर कुंडली के तीसरे घर में\r\nहै यहां पर दिग बली नहीं है कहीं लिखा है\r\nअच्छा ये जुपिटर का है गुरु का है शायद\r\nडिग्री गुरु का होगा मिस प्रिंट हो गया है\r\nजुपिटर आपको पता है कि यहां यहां यहां\r\nडिबली होता है इस केस में थ हाउस का लड\r\nदिगली नहीं है सबसे इंपोर्टेंट अगेन वीनस\r\n90 प्र के आसपास दिगली है अब गौर से समझिए\r\nयहां\r\nपर दो प्लाइट इनके आपको दिगल में दिखेंगे\r\nएक दिखेगा मरकरी और एक दिखेगा वीनस शुक्र\r\nऔर बुध पिछले चार्ट में\r\nपिछले चार्ट में वीनस दिगली प्लानेट था\r\nअकेला य वीनस और मरकरी दिगली प्लानेट है\r\nयह चार्ट है बिल गेट्स का थड हाउस है आपका\r\nऑनलाइन और मेन कोडिंग\r\nजो कोडिंग जो आप यूज करते हैं ट इ थड हाउस\r\nऔर सब जानते हैं की कॉलेज डप आउट करने के\r\nबाद इन्होने जो चीज सीखी वा क्या था\r\nकोडिंग माइक्रोसॉफ्ट और बाकी सब फिर\r\nहिस्ट्री है हम सब जानते हैं ठीक है क्या\r\nफर्क आया बिल्कुल वीनस है थर्ड हाउस में\r\nहै साथ में मरकरी भी इनका बुध भी इनका डबल\r\nयानी कि दिग बल हो जाता है इस वजह से\r\nमरकरी थर्ड हाउस सेकंड हाउस वीनस का\r\nकॉमिनेशन बनता है अगेन मैं यहां पर करियर\r\nएनालिसिस पूरी तरह से अभी नहीं कर रहा हूं\r\nमैं यह बता रहा हूं कि अगर थ हाउस का लस\r\nबबली होके किसी हाउस में है तो मैं\r\nमानूंगा कि हा उस हाउस से संबंधित काम किए\r\nजाने चाहिए अदर वाइज मैं कुंडली के दिग\r\nबली ग्रहो को लेक ज्यादा बेहतर रिजल्ट की\r\nकल्पना कर सकता हूं चलिए अगला चार्ट देखते\r\nहैं अगेन जुपिटर गुरु थ हाउस का लॉर्ड है\r\nपांचवे घर में है केवल टबल में 12 का सॉरी\r\nदिगल में 12 का दिगल मिला हुआ है कुंडली\r\nके तीन ग्रह देखते हैं शनि 87 पर 87 पर\r\nदिबल के साथ बुध मरकरी और वीनस चार्ट है\r\nश्री रवींद्रनाथ टैगोर जी का जिन्हे\r\nराइटिंग वर्क के लिए जो मरकरी रिप्रेजेंट\r\nकरता है पोएट्री लिखने के लिए गीतांजली एक\r\nकाव्य लिखा जिसके लिए इनको नोबल प्राइज\r\nमिलता है सोशल सर्विस की है साहित्य में\r\nबहुत बड़ा इनका योगदान रहा है और सोशल\r\nवर्कर भी रहे हैं यहां पर अगर आप गौर से\r\nसमझे क्या जुपिटर का इस डायरेक्शन में\r\nहोना मुझे फिफ्थ हाउस के रिजल्ट या मेरे\r\nकाम में फिफ्थ हाउस को जोड़ता है या बुध\r\nमरकरी सैटन शनि और वीनस शुक्र इनके योगदान\r\nको मैं इंपॉर्टेंट मान सकता हूं 200 चार्ट\r\nके एप्लीकेशन में हमें ये समझ आया तो\r\nदिग्बी कि थ लॉर्ड किस हाउस में है वहां\r\nअगर दिगभ हो तो बिल्कुल नेटिव को बहुत हद\r\nतक बहुत ज्यादा इस हाउस का रोल मिल जाता\r\nहै अगर ऐसा नहीं होता तो चार्ट को बेटर\r\nकरने के लिए करियर को या लाइफ के अलग-अलग\r\nहिस्सों को बेहतर करने के लिए मैं दिगली\r\nप्लानेट का उपयोग कर सकता हूं उसका अट कर\r\nसकता एक और एग्जांपल मैं आपको एक और चीज\r\nबताता हूं अटल बिहारी वाजपेई जी और\r\nनरेंद्र मोदी जी दोनों के चार्ट वृश्चिक\r\nलग्न के है सेम है ठीक है इनका सूर्य अटल\r\nबिहारी वाजपेई जी का सूर्य यहां पर है\r\nदिगली नहीं है नरेंद्र मोदी जी का सन यहां\r\nपर है और यह दिग बली है दोनों\r\nप्रधानमंत्री रहे लेकिन फर्क आप समझ सकते\r\nहो थ हाउस का लॉर्ड दिगली ऊपर से सूर्य\r\nदिग बली तो जो प्रभु जो हाइट जो ऊंचाई\r\nसूर्य यानी सूर्य किसका कारक है आप सभी को\r\nपता है तो प्लानेट जब\r\nदिगबरा क्या है उसके वो बहुत अच्छे से\r\nदेता है जिस हाउस में है उसको अलाइन कर\r\nसकते है और जिस साइन में है जिस राशि में\r\nहै इन तीन चीजों को आप अलाइन कर सकते हैं\r\nइस पूरे शोध का इस पूरे रिसर्च का पर्पस\r\nयही था कि टबल के अलग अलग बल में ऐसा क्या\r\nहै जिसको हम एक एक करके स्टडी करें तो\r\nक्या कुछ और डीप इन चीजों को समझ सकते हैं\r\nआप चीजें पढ़ते हैं अगर मैंने डबल पढ़ा है\r\nतो केवल बस स्ट्रेंथ देख के अगर मैं\r\nएनालिसिस करता हूं थोड़ा सा मेरे हिसाब से\r\nये वीकनेस है या कमी है हमें जानना चाहिए\r\nकि शड बल बनता कैसे है इसका हर एलिमेंट हर\r\nतत्व करता क्या है उसका रोल क्या है और वो\r\nकहां बेटर रिजल्ट दे सकता है समझ पा रहे\r\nहैं तो ये केवल एक शोध है जो अभी मैंने\r\nआपके साथ शेयर की है डबल को और डिटेल में\r\nभी जानेंगे अलग-अलग बल को भी हम स्टडी\r\nकरेंगे और उससे रिलेटेड भी कुछ रिसर्च\r\nवर्क है जो मैं आपके साथ शेयर कर दूंगा आज\r\nके लिए मैं इतना ही कंप्लीट कर रहा हूं\r\nक्योंकि कुछ एडिशनल चार्ट भी हम लोग दे\r\nरहे हैं"},{"topic":"रवि-योग- Part -2-जानिए कुंडली में सूर्य से बनने वाले महत्वपूर्ण योगों को-","text":"गुड मॉर्निंग\r\nआज तो आज हम बात करेंगे सूर्य योग रवि योग\r\nयानी की सूर्य से बनने वाले कुछ\r\nमहत्वपूर्ण योग जो हमारी कुंडली में बनते\r\nहैं और साथ में हम समझेंगे की इस तरह के\r\nयोग बनने मात्रा से ही कम हो जाता है या\r\nउनके फल कथन करने के लिए कुछ चीज जरूरी\r\nहोती है तो समझते हैं चलिए पहला योग्य\r\nहमारा वैसी योग ये शोभा भी हो सकता है आप\r\nवैसे भी हो सकता है या अशुभ जैसे बोलते\r\nहैं तो समझ लेते हैं पहले की यह होता क्या\r\nहै देखिए चंद्रमा को इसमें शामिल नहीं\r\nकरेंगे और जैसा आप यह ऊपर पंच ग्रह देख\r\nसकते हैं केवल इनके साथ यह कांबिनेशन\r\nबनेगा तो जब आपकी कुंडली में सूर्य से\r\nदूसरे घर में दूसरे भाव में कोई ग्रह हो\r\nइन पांचो में से तो वैसी योग बनता है अब\r\nअगर यह शुभ ग्रह\r\nतो पाप वैसी का निर्माण होगा एक एग्जांपल\r\nदेख लेते हैं कैसे बनेगा देख लीजिए\r\nयहां पर तीसरे घर में यानी थर्ड हाउस में\r\nआपको सूर्य दिखाई दे रहा है तो इस वैसी\r\nयोग को बनने का मतलब है की सूर्य का अगला\r\nभाव यानी की चौथा घर मैं कोई गैर पांचो\r\nमें से होना चाहिए तो यहां पे मंगल है\r\nयानी की इस कुंडली को देख के बोला जा सकता\r\nहै की यहां पे वैसी योग बन रहा है\r\nअब ऐसे योग में जन्म जातक बहुत भाग्यशाली\r\nहोता है\r\nबहुत गुना से संपन्न होता है और प्रतिष्ठा\r\nख्याति मिलती है उसे बहुत और अरिस्टो के\r\nलगभग या तो उच्च कुल या राजा के समान उसका\r\nजीवन होता है पर अब ऐसे ही होगा आपको कई\r\nसारी कुंडली में मिल जाएंगे लेकिन वो फलित\r\nनहीं होते तो उसका कारण क्या है थोड़ा वह\r\nभी समझ लेते हैं और एक एग्जांपल देखते हैं\r\nअब आपके सामने कुंडली है तो हम बात कर रहे\r\nहैं वैसी योग की तो सबसे पहले हम देखेंगे\r\nसातवें घर में तीन ग्रह आपको दिखाई देंगे\r\nतो एक-एक करके देखते हैं की कौन से ग्रह\r\nइसमें वैसी योग बनाते हैं हालांकि देखा\r\nजाए तो तीनों बनने चाहिए लेकिन पहले बात\r\nकरते हैं मंगल की\r\nक्या मंगल और सूर्य मिलकर वैसी योग का\r\nनिर्माण कर रहे हैं और कर रहे हैं तो क्या\r\nवह रिजल्ट देगा देखिए गौर से नीचे देखिएगा\r\nसूर्य की जो डिग्री है सूर्य है 22° का\r\nकर्क राशि में और मंगल है 21 डिग्री का\r\nसिंह राशि में यानी की एक राशि आगे तो इन\r\nदोनों के बीच का डिफरेंस लगभग हुआ 29\r\nडिग्री के आसपास\r\nजब कोई ग्रह एक दूसरे से 29 30 डिग्री के\r\nआसपास की दूरी पे है तो वो कांबिनेशन कम\r\nनहीं करता यानी की इसमें मंगल का कोई रोल\r\nनहीं होगा वैसी योग के निर्माण में अब बात\r\nकरते हैं सूर्य के साथ बुद्ध की\r\nबुद्ध की डिग्री है 13 डिग्री यानी की यह\r\nसूर्य से करीब करीब 9 डिग्री दूर है\r\nक्योंकि बुध एक एक्सेप्शन है जो सूर्य के\r\nसाथ अस्त्र नहीं होता लेकिन इसका यह मतलब\r\nनहीं है की वो पूरा प्रभाव देगा सूर्य और\r\nबुध में 10 डिग्री का फर्क होना चाहिए पर\r\nये नौका है तो इसका जो प्रभाव होगा वो\r\nवैसी योग के अनुसार थोड़ा धोना चाहिए अब\r\nचूंकि बुध आपका एक त्रिकोण का मलिक है\r\nतीसरी राशि बुद्ध की है और बुद्ध आपका\r\nछठवें राशि यानी की आठवें घर का मलिक है\r\nतो ये न्यूट्रल हो जाता है यानी की सैम हो\r\nजाता है तो सूर्य और बुध के साथ जब ऐसी जो\r\nहोगा मतलब की जब दशा चलेगी बुध की तो\r\nरिजल्ट आपको पूरे वैसी योग के रिजल्ट नहीं\r\nमिलेंगे अब बात करते हैं सूर्य के साथ\r\nशुक्र की यानी की वीनस की देखेगा वीनस\r\nस्कूल\r\nको का मलिक है तो इसका मतलब वीनस बहुत\r\nपावरफुल है इस कुंडली के लिए दूसरा बिजनेस\r\nकी डिग्री है दो यानी की ये सूर्य से 20°\r\nदूर है और ये विषम राशि में है यानी की\r\nबाल अवस्था में है 2 डिग्री मतलब\r\nबाल्यावस्था हो गई इसके लिए क्योंकि\r\nचक्र\r\nवैसी योग निर्माण कर रहा है केंद्र और\r\nत्रिकोण का मलिक है जो केंद्र में आके\r\nबैठा हुआ है तो बहुत मजबूत हो जाता है\r\nहालांकि रोल उसका कम होगा डिग्री उसकी कम\r\nहोगी तो जब शुक्र की दशा चलेगी तो इन\r\nतीनों ग्रह में सबसे ज्यादा इफेक्ट आपको\r\nशुक्र की दशा में मिलने वाले से ओके\r\nहालांकि वो भी पूरे 100% रिजल्ट नहीं\r\nहोंगे अब जब हम प्रिडिक्शन करेंगे तो क्या\r\nहम यह बोलेंगे की राजा के समान होगा जातक\r\nया वही चारों चीज जो हमने पहले देखी\r\nजिन्हें इसका परीक्षण हम करेंगे की यह\r\nदेखिए जिस घर में\r\nसूर्य की राशि सिंह और इसे बनाने वाला\r\nग्रह है खुद से यानी\r\nकरता है और अपने ही घर में करता है तो\r\nइसका मतलब इसका में प्रिडिक्शन होगा की\r\nजातक को सेवंथ हाउस रिलेटेड जितनी भी चीज\r\nहैं उन सब में सब चीज मिलेगी उन्ना\r\nफॉर्च्यून मिलेगा उसमें प्रतिष्ठा मिलेगी\r\nऔर उससे सीधी जितने भी फंक्शन है उसमें सब\r\nचीज उसको मिल बताएंगे तो कभी वैसे योग्यता\r\nके योग बनने का मतलब एग्जैक्ट शब्द नहीं\r\nहोते हमें देखना चाहिए किस घर में बंद रहे\r\nहैं और किस हद तक बन रहे हैं चलिए आगे\r\nबढ़ते हैं\r\nफिर वापसी हो वीडियो भी से है वही पंच\r\nप्लैनेट की बात करेंगे बस फर्क इतना है की\r\nअब ये पांचो में से कोई भी ग्रह सूर्य से\r\nपर्व स्थान में होंगे तो वासी योग बनेगा\r\nअगर पाप ग्रह होगा तो पापा वासी बनेगा और\r\nशुभ ग्रह होगा तो shubhvasi बनेगा पहले\r\nएग्जांपल देख लेते हैं सूर्य आपका\r\nपांचवी घर में बैठा है और पांचवे से 12\r\nयानी चौथा घर जहां पर आपका मरकरी यानी बुध\r\nबैठा है राहु केतु को हम नहीं गिनते व\r\nकिसी भी योग के लिए अभी तक हमने देखा केवल\r\nपंच प्लैनेट की हम बात कर रहे हैं चंद्रमा\r\nको छोड़ दे रहे हैं तो यह तो दिखता है की\r\nवहां से जो बनता है ऐसे योग में जन्म में\r\nजाट को क्या मिलता है यह देखते हैं\r\nव्यक्ति दानी होता है स्वभाव से राजा का\r\nसहयोगी या राजनीति में हो सकता है किसी\r\nबड़ी मिनिस्टर के साथ हो सकता है और बहुत\r\nबड़ी ख्याति मैन प्रतिष्ठा उसको हासिल\r\nहोती है अब बात करते हैं की जो एग्जांपल\r\nहै हमारे सामने\r\nकी प्लैनेट सो गया अशुभ देखिए फंक्शनल\r\nबेनिफिट की बात नहीं कर रहे इस कुंडली के\r\nलिए इस कुंडली के लिए जिसका लग्न है मेष\r\nइस कुंडली के लिए क्या बुद्ध इस समय\r\nबेनिफिशियल maniffic तो देखिए बुद्ध तीसरे\r\nघर का मलिक है और छठवें घर का मलिक है\r\nयानी की यह मलेफिक हुआ हाउस के हिसाब से\r\nइन दोनों घर के मलिक बेनिफिट yanefit में\r\nडिफरेंस हमें पता है हम लोगों को तो यह\r\nहुआ यानी की पाप ग्रह हुआ दूसरा बुद्ध\r\nन्यूट्रल होता है लेकिन जिसके साथ बैठता\r\nहै वैसा रूप धारण कर लेता है तो केतु के\r\nसाथ बैठा है केतु फिर से एक प्लैनेट है\r\nसाथ में राहु इसको देख रहा है एस्पेक्ट\r\nकरेगा यानी की तीनों तरह से बुद्ध मलेफिक\r\nहै तो यह जो योग है यहां जो बनेगा यह शुभ\r\nवासी नहीं बनेगा ये अशुभ वासी बनेगा तो\r\nकेवल यह देख लेना की सूर्य से बार भी अगर\r\nकोई घर होगा तो ये आपका योग बन जाएगा यह\r\nफल खत्म सही नहीं होगा अब एक और चीज इसमें\r\nआती है अगर मैंने यह देख लिया की सूर्य से\r\n12 अशुभ ग्रह तो क्या यह कंफर्म\r\nashubhwasi बनाएगा जैसा हमने यहां देखा तो\r\nथोड़ी सी इसकी विवेचना और करते हैं\r\nमैंने कहा मरकरी के यहां पर चार डिग्री 20\r\nमिनट का है यानी की इसका अंश है अभी हम\r\nइसका शेड्यूल भी देखेंगे अगर प्रिडिक्शन\r\nपे जाएंगे लेकिन अभी हम बात करें तो बुद्ध\r\nहै चार नंबर राशि में जो एवं साइन है यानी\r\nकी सैम सैम राशि है सैम राशि का मतलब है\r\nकी 4 डिग्री का प्लान यानी की जीरो से 6\r\nडिग्री में प्लैनेट माना जाता है तो यहां\r\nपे बुद्ध जो है मृत प्लैनेट है\r\nठीक है तो जब मैं किधर से आएगी तो क्या वह\r\nअशुभ वासी के पूरे रिजल्ट देगा इसका मतलब\r\nनहीं देगा तो इस कुंडली में वासी योग है\r\nऔर ashubhwasi है लेकिन अशुभ के भी प्रभाव\r\nपूरे नहीं मिलेंगे क्योंकि वो देने वाला\r\nप्लैनेट जो है अभी जो स्थिति दिख रही है\r\nउसके हिसाब से मृत अवस्था में है अब और\r\nकुछ इफेक्ट या कांबिनेशन होंगे कुंडली में\r\nवो हम आगे इंटरप्रेट करेंगे तो केवल योग\r\nदेख लेने से कम नहीं होता आगे बढ़ते हैं\r\nदोनों तरफ यानी की अब सूर्य के दूसरे घर\r\nमें और सूर्य के बारे में यानी सूर्य के\r\nबाद में और सूर्य से पहले कोई ग्रह होना\r\nचाहिए तो वो उभरे योग बनाता है अभी बात\r\nकरते हैं\r\nदेखिए सूर्य आपका 11वें घर में बैठा है\r\nयहां पे तो सूर्य से दूसरा घर हुआ बार-बार\r\nजहां गुरु बैठा हुआ है और सूर्य से 12\r\nयानी की सूर्य से पहले मंगल बैठा हुआ है\r\nतो यह हुआ\r\nजहां पर सूर्य के दोनों तरफ गृह होते हैं\r\nअब ऐसे जातकों को क्या मिलता है ऐसे जातक\r\nबहुत क्वेश्चन बहुत अच्छे लेवल के अच्छे\r\nवक्त होते हैं जल्दी और फेमस होते हैं\r\nधनवान होंगे और प्रतिष्ठा कीर्ति प्राप्त\r\nहोती है और दूसरा दिखने में बहुत सुंदर\r\nहोते हैं अच्छे मोहक होते हैं अट्रैक्टिव\r\nहोते हैं\r\nहै अब हम देखते हैं की यह जो योग हमारे\r\nसामने है कुंडली में क्या यह अच्छा है या\r\nबुरा है पाप है या शुभ है देखिए पहले बात\r\nकरते हैं मंगल की जो की मंगल कुंडली का\r\nलग्नेश खुद है फिर चाहे वह बचका था उसका\r\nमलिक क्यों ना हो लग्नेश को आठवीं घर का\r\nबुरा रिजल्ट नहीं मिलता तो इसलिए मंगल इस\r\nकुंडली का बेनिफिट प्लैनेट है और दूसरी\r\nचीज मंगल तस्वीर राशि में बैठा है जो मंगल\r\nके उच्च राशि है तो मंगल लग्नेश होकर उच्च\r\nराशि में बैठा है यानी की यह योग पॉजिटिव\r\nहै गुरु देखते हैं जुपिटर त्रिकोण का मलिक\r\nहै और सबसे स्ट्रांग त्रिकोण कुंडली का\r\nसबसे महत्वपूर्ण भाव नवा भाव होता है ये\r\nहम जानते हैं पढ़ चुके हैं और 84 में यानी\r\nकी खुद की राशि में बैठा हुआ है यानी\r\nबेनिफिट प्लैनेट यहां पर खुद की राशि में\r\nबैठा है तो यह भी शुभ ग्रह कहलाएगा तो ऐसा\r\nयोग इस स्थिति में इस कुंडली के लिए जब भी\r\nजुपिटर के दशा आएगी या मंगल के दशा आएगी\r\nतो पूरे परिणाम वीडियो के देने वाले हैं\r\nऔर जहां तक को यह सारे रिजल्ट मिल सकते\r\nहैं बहुत हद तक हालांकि 10 11 12 ये तीनों\r\nघर के रिजल्ट ज्यादा मिलेंगे और आप गौर से\r\nदेखेंगे तो 11वां घर आपका गेम्स का\r\nदसवां करें आपके कर्मों का स्टेटस का और\r\nबार-बार घर आपका\r\nआध्यात्मिक से लेकर चीजों का भी कहलाता है\r\nमोक्ष का कहलाता है आपके इन्वेस्टमेंट का\r\nकहलाता है तो सारी चीज यहां पे आपको मैच\r\nहोती मिल जाएंगी और चूंकि सूर्य कारक है\r\nआपका तेज का ओज का\r\nतो यह सारी चीज यहां पर मैच हो सकती है तो\r\nआपको सबसे पहले देखता है की योग बन रहा है\r\nकी नहीं दूसरा योग बन रहा है वह अशुभ है\r\nया अशुभ है तीसरा विश्व योग को बनाने वाले\r\nग्रह ताकतवर है या नहीं है चलिए एक बहुत\r\nमहत्वपूर्ण योग कुंडली का आदित्य योग\r\nजिसके बारे में कई बार आपने सुना होगा\r\nदेखिए\r\nजब सूर्य बुध कुंडली में एक साथ किसी भाव\r\nमें हो तो आकृति योग होता है और ये योजना\r\nआपको ज्यादातर कुंडली में मिल जाएगा\r\nक्योंकि नॉर्मल ही सूर्य और बुद्ध साथ में\r\nरहते हैं तो एक एग्जांपल है आठवीं घर में\r\nदोनों घर बैठकर हैं बैठे हैं क्या यह बता\r\nदेती हो बनाते हैं यह डिपेंड करेगा\r\nहम पहले इसका वो देख लेते हैं की\r\nक्या-क्या चीज होती है बंदों के पास ऐसा\r\nव्यक्ति इंटेलिजेंट होता है और स्किलफुल\r\nहोता है\r\nजाना पहचाना नाम होता है और सेल्फ\r\nरिस्पेक्ट बहुत मिलती है और सारे सुख\r\nभौतिक सुख सुविधा है उसको प्राप्त होती है\r\nऐसा कहा जाता है बुलाती योग में अब मैन\r\nलीजिए इस कुंडली में सूर्य की स्टेज है\r\n26° 35 मिनट और मरकरी का है 28 डिग्री 30\r\nमिनट\r\nक्योंकि सूर्य के पास कोई भी प्लैनेट आने\r\nसे वह अस्त हो जाता है पर मरकरी एक\r\nएक्सेप्शन है लेकिन महर्षि पाराशर ने बहुत\r\nस्पष्ट रूप से कहा है की इनके बीच में\r\nकिसी बड़े राज्यों के निर्माण के लिए 10\r\nडिग्री का डिफरेंस होना चाहिए तो अगर यह\r\nकेवल 2 डिग्री का फर्क है तो यह योग बनने\r\nके बाद भी रिजल्ट नहीं आएगा बुद्ध पूरे\r\nप्रभाव नहीं देगा\r\nतो अगर d9 में भी बता देती हो बंद रहा है\r\nतो आप यह का सकते हैं की यह बहुत स्ट्रांग\r\nहै जैसे अगर हम इस कुंडली के बात करें तो\r\nआप देखेंगे की सूर्य यहां पर मेष राशि में\r\n26 डिग्री का है यानी की आठवें हिस्से में\r\nजाएगा यानी की 9 मार्च देखेंगे यानी अगर\r\nमैं ऐसी कुंडली को नमन तो आपको सूर्य\r\nमिलेगा तीसरे घर में यानी की आठवीं राशि\r\nमें यहां पे सूर्य मिलेगा और मरकरी 28° का\r\nहै यानी 27° 40 मिनट से 30° के आसपास\r\nजाएगा दवे भाग में तो यानी की नवे घर में\r\nआपको मरकरी मिल जाएगा नौ मांस में\r\nयह हम शायद स्टडी कर चुके हैं ना रोमांस\r\nको बनाना कैसे बनता हालांकि आपको बने हुए\r\nमिल जाते हैं तो जब हम इसका naumans\r\nबनाएंगे तो सूर्य पहुंच जाएगा आठवीं राशि\r\nमें और मरकरी पहुंच जाएगा नवीन राशि में\r\nदोनों अलग-अलग हैं नमन पदार्थ योग नहीं\r\nबनता है तो इसका मतलब यही योग फलित नहीं\r\nहोगा तो इस तरह से हम यूजुअली इन चीजों को\r\nकैलकुलेट कर सकते हैं और फिर वही में\r\nइंपॉर्टेंट पॉइंट जो हमारे पास बताते हैं\r\nलग्नेश का बलवान होना जरूरी है ग्रहों का\r\nबलवान होना जरूरी है और पाप और पुण्य\r\nग्रहों का अध्ययन कर\r\nAll\r\nFrom the series"},{"topic":"सम्पूर्ण ज्योतिष - सीखिए सम्पूर्ण पाराशरी ज्योतिष-A New Beginning of Astrology- Power of Vedas -","text":"गुड मॉर्निंग\r\nइंजेक्शन अच्छा रहा होगा आप लोगों का गुड\r\nचलिए तो जल्दी से आज का ब्रिज\r\nसमझेंगे\r\nयहां पर\r\nस्टडी कर सकें ताकि हमारे जो प्रिडिक्शन\r\nहै वह बहुत एक्यूरेट और सटीक हो सके ठीक\r\nहै\r\nयह चीज है यह साइंस यह विज्ञान इतना पहले\r\nलिखा गया क्या यह आज भी कम करता है\r\nअब क्योंकि जिन चीजों की सार्थकता खत्म हो\r\nजाती है वह विलुप्त हो जाते हैं सब मानते\r\nहैं चीज लेकिन ज्योतिष विज्ञान आज तक चला\r\nए रहा है और करोड़ लोग इस पर भरोसा करते\r\nहैं तो इसका मतलब यह कम तो करता है अब\r\nबातें की चीज यह है की हमारी समझ कितनी है\r\nहम इसको कितना समझते हैं और कितने अच्छे\r\nरिजल्ट दे पाते हैं\r\nयूजुअली ना ऐसा कहा जाता है की\r\nएस्ट्रोलॉजी सा लैंग्वेज\r\nएक भाषा है इफ यू अंडरस्टैंड दिस लैंग्वेज\r\nअगर आप इस भाषा को समझ लेते हैं तो पूरा\r\nस्पेस अंतरिक्ष प्लैनेट ग्रह नक्षत्र आप\r\nसे बातें करने लगते हैं इसका मीनिंग है की\r\nआपको इनकी बहुत गहरी समझ हो जाती है और\r\nआपके प्रिडिक्शन लेवल बहुत हाई लेवल के हो\r\nजाते हैं तो आपके 6 महीने के कोर्स में हम\r\nदेखेंगे की क्या ऐसा होता है और ट्राई\r\nकरेंगे ऐसा करने का तो समझते हैं की इस\r\nकोर्स में हम लोग क्या-क्या कवर करने वाले\r\nहैं\r\nदेखिए सबसे पहले ना कुंडली एनालिसिस में\r\nप्रॉब्लम क्या आती है पहला की मैं तेरे\r\nसामने चैट है मैं करूं क्या उसका कैसे\r\nएनालाइज करूं क्या देखूं किन-किन चीजों पर\r\nविचार करूं दूसरी समस्याएं मुझे यह पता है\r\nलेकिन मैं चार्ट में इंटरप्रेट कैसे करूं\r\nफाइनल रिजल्ट कैसे निकल के डन अपने जातक\r\nको या अपने क्लाइंट को\r\nफिर ये सब करने के बाद भी मेरे प्रिडिक्शन\r\nरोंग क्यों हो जाते हैं गलत रिजल्ट क्यों\r\nए जाते हैं\r\nउसके बाद समस्या है मैंने कोई उपाय दिया\r\nकोई रेमेडी भी वह कम नहीं करती या वो गलत\r\nहो गई मतलब उसका रिजल्ट नहीं आया तो आम\r\nतौर पर यह चार से पंच समस्याएं हैं जो हर\r\nएक एस्ट्रोलॉजर के पास आती है की\r\nप्रिडिक्शन क्यों प्रॉपर नहीं होते रिजल्ट\r\n100% मेरे क्लाइंट को क्यों नहीं मिलता\r\nइसीलिए हम जो कोर्स की बात करते हैं वह\r\nकरते हैं संपूर्ण ज्योतिष तो समझ लेते हैं\r\nइसमें हम क्या-क्या कवर करने वाले हैं\r\nसबसे पहले हम बात करेंगे\r\nआपके 12 हाउस यानी की कुंडली के 12 घर और\r\nवो हमें क्या देते हैं उसके अलावा 12\r\nराशियां उनके स्वभाव क्या है और इन\r\nराशियों को कैसे उसे करते हैं कुंडली में\r\nफिर आते हैं आपके नवग्रह यानी की 9\r\nप्लैनेट्स इनका स्वरूप कैसा है हर प्लैनेट\r\nकी अपनी खासियत है वह क्या है और यह कैसे\r\nकम करते हैं इन प्लैनेट की एस्पेक्ट क्या\r\nहै ये एक दूसरे को कैसे देखते हैं इनकी\r\nदृष्टि yaspect के बारे में समझेंगे\r\nप्लैनेट्स के आपस में एक दूसरे से क्या\r\nरिलेशन है फ्रेंड्स है एनिमी है वो सब\r\nसमझेंगे और चार कारक और नैसर्गिक कारक ये\r\nमें हो जाता है की प्लैनेट का ग्रह का खुद\r\nका अपना जो स्वभाव है वो कैसे रिफ्लेक्ट\r\nहोता है रिजल्ट में इन चीजों के बारे में\r\nहम समझेंगे तो लग्न चार्ट वाले टॉपिक में\r\nये सारी चीज कवर हो जाएंगी आगे बढ़ते हैं\r\nमहर्षि पाराशर ने कहा की कुंडली के\r\nसाथ-साथ जब आपको किसी एक भाव को बहुत\r\nगहराई में जाकर पढ़ना हो इंडेक्स स्टडी\r\nकरनी हो तो उन्होंने शोल्डर वर्ग यानी की\r\nडिविजनल चार्ट की रचना की तो हम लोग यह\r\nपूरे 16 डिविजनल चार्ज समझेंगे की इनको\r\nलग्न चार्ट के साथ मैच करके कैसे बेहतर\r\nप्रिडिक्शन किया जाता है और ये सारे चार्ट\r\nहम विद एग्जांपल प्रैक्टिकल कुंडली के साथ\r\nमें समझने वाले हैं ठीक है तो इससे आपकी\r\nपकड़ और मजबूत हो जाएगी और आप इंडक्ट\r\nस्टडी करके बेहतर रिजल्ट दे पाएंगे\r\nकस्टमर जो की उनको यह भी पता था की आने\r\nवाले समय में मनुष्य की जो मानसिक\r\nक्षमताएं हैं वह इतने विकसित नहीं रह\r\nपाएंगे तो उन्होंने एक बहुत सरल सिद्धांत\r\nदिया अष्ट वर्ग का जहां कैलकुलेटेड आपके\r\nसामने वो होता है विटामिन उसको देख के आप\r\nएक आइडिया लगा सकते हैं की इस व्यक्ति का\r\nयह ग्रह इस राशि में है तो क्या यहां यह\r\nबेनिफिट है या maniffic है अच्छा है या\r\nबुरा है ये एक बहुत जल्दी आपको आइडिया दे\r\nदेता है लेकिन केवल को पुरी तरह से कुंडली\r\nएनालिसिस में उसे नहीं करना चाहिए इससे\r\nपूरे 100% रिजल्ट नहीं आते लेकिन फिर भी\r\nयह बहुत हद तक बेनिफिशियल होता है देखेंगे\r\nवो कैसे उसे किया जाता है\r\nफिर आता की बेसिक गाइडलाइन कुंडली\r\nएनालिसिस करने से पहले करना क्या है\r\nफर्स्ट नंबर पर क्या करना है सेकंड पे\r\nक्या करना है थर्ड पे क्या करना है कैसे\r\nस्टफ फॉलो करनी है ताकि सटीक रिजल्ट ए सके\r\nतो वो गाइडलाइन हम लोग डिस्कस करेंगे\r\nइंटरप्रिटेशन के साथ में\r\nफिर जैसा आप जानते हैं महादशा अंतर्दशा\r\nप्लैनेट अपने रिजल्ट इसी में देते हैं\r\nक्योंकि महर्षि पाराशर ने 10 से ज्यादा\r\nदशाओं का वर्णन किया है और हम लोग आम तौर\r\nपर vimshotri दशा को ही मानते हैं तो हम\r\nइसके साथ में तीन से चार और दूसरी दशाएं\r\nदेखेंगे क्योंकि कभी-कभी आपको लगेगा की\r\nआपके जातक की एक महादशा और दशा चल रही है\r\nअंतर्दशा लेकिन उसके जो रिजल्ट है वो\r\nएक्चुअल में वो नहीं ए रहे जो आने चाहिए\r\nउसका कारण हो सकता है की उसे जातक पर\r\nदशा का प्रभाव ना हो उसके ऊपर राशि दशा का\r\nप्रभाव हो सु ताशा का प्रभाव हो नारायण\r\nदशा का प्रभाव हो तो इन डिपेंड्स तो हम\r\nलोग 3 से 4 एडिशनल दशहरे देखेंगे और उनसे\r\nसंबंधित प्रैक्टिकल एग्जांपल भी करेंगे की\r\nकैसे रिजल्ट चेंज हो जाते हैं\r\nफिर आता है गोचर अब क्योंकि महादशा\r\nअंतर्दशा की बात करेंगे तो साथ में गोचर\r\nको भी देखना जरूरी होता है गोचर का मतलब\r\nहै की जिस समय आप प्रिडिक्शन कर रहे हो\r\nउसे समय ग्रहों की स्थिति क्या है क्योंकि\r\nग्रह अपने स्थान बदलते रहते हैं राशियां\r\nबदलते हैं तो जब आप प्रिडिक्शन कर रहे हो\r\nया जिस समय के लिए प्रिडिक्शन कर रहे हो\r\nउसे समय कौन सा ग्रह किस राशि में है और\r\nवो क्या रिजल्ट देगा इसलिए गोचर एनालिसिस\r\nजरूरी हो जाता है ट्रेडिशनल चार्ट बोलते\r\nहैं इसे या बनाना सीखेंगे कुंडली पर\r\nअप्लाई करना सीखेंगे\r\nफिर आता है अगला बहुत से लोग इस पर ध्यान\r\nनहीं देते अगला का मतलब होता है\r\nऑब्स्ट्रक्शन बढ़ाएं कभी-कभी आपको लगेगा\r\nकी एक कुंडली में एक भाव का स्वामी सब कुछ\r\nअच्छा है ठीक है पर फिर भी पर्सन को\r\nरिजल्ट नहीं मिल रही कोई बुरी एस्पेक्ट\r\nनहीं है उसके पास उत अच्छी है लेकिन जातक\r\nको 100% रिजल्ट नहीं मिलते हैं उसका कारण\r\nहो सकता है की उसे घर पे या उसे घर के\r\nमलिक पे कोई बुरी और गला ए रही हो ये अगला\r\nकैसे आती है किन प्लैनेट्स से आती है और\r\nइसका सॉल्यूशन क्या है ये हम अगला वाले\r\nटॉपिक में समझेंगे लेकिन ये बहुत जरूरी हो\r\nजाता है\r\nकैसा है\r\nअब अगर मैं बात करूं अर्थ लग्न और अर्ध\r\nपड़ा की तो ये बताया की ये दुनिया समाज या\r\nलोग उसे व्यक्ति को कैसे देखते हैं उसके\r\nप्रति कैसा नजरिया रखते हैं हर भाव से\r\nसंबंधित एग्जांपल के लिए जातक आपके पास\r\nआता है और कहता है की मैं अपने जॉब में कम\r\nकरता हूं पुरी मेहनत करता हूं लेकिन मेरे\r\nसीनियर्स को मेरे कालिक को ना अन मेरा कम\r\nदेखता नहीं है मुझे प्रमोशन नहीं मिलता यह\r\nउन्हें ये लगता है की मैं कम करता ही नहीं\r\nहूं अब आपको दिख रहा है की इसका प्रोफेशन\r\nया टेंट हाउस का प्लैनेट अच्छा है एफर्ट\r\nभी अच्छे दल रहा है फिर उसको रिजल्ट क्यों\r\nनहीं मिलते तो हो सकता है प्रॉब्लम उसके\r\narundha पड़ा में हो लोगों की परसेप्शन\r\nमें हो लोगों के नजरिया में हो तो मैं\r\nरेमेडी उसको उसके स्पेसिफिक प्लैनेट की\r\nदूंगा या arundha से संबंधित प्लैनेट की\r\nदूंगा यह मायने रखता है तो इसकी जरूरी हो\r\nजाता है की हम अरदा लगने के स्टडी करें\r\nसाथ में घाटी लग्न आपको यह बताता है की एक\r\nजातक लोगों को समाज को अपने परेशानियों को\r\nदुनिया को यह सब किस नजर से देखता है वो\r\nकैसे चीजों को देखता है कैसे उनकी वैल्यू\r\nकरता है\r\nआपके पास पॉलीटिशियन की कुंडली हो कोई ऐसी\r\nकुंडली हो जिसमें नाम पावर अथॉरिटी की बात\r\nकी जा रही हो तो खाती लग्न बहुत\r\nमहत्वपूर्ण हो जाता है आगे समझेंगे\r\nएग्जांपल से की कैसे इनका उसे किया जाता\r\nहै\r\nफिर आता है महत्वपूर्ण योग है कुछ लगभग एक\r\n300 कांबिनेशन बनते हैं सुना होगा आपने\r\nकिसी का राजयोग है या फिर\r\nduryog है इस तरह की चीज रहती हैं राइट तो\r\nहम 300 पूरे योग को डिस्कस नहीं करेंगे\r\nकभी आपकी क्लासेस में हान 100 में से हम\r\nलोग डिस्कस करेंगे विथ प्रैक्टिकल\r\nएग्जांपल और बाकी के आपको नोट्स मिलके अभी\r\nमिल जाएंगे तो आप उसमें एनालिसिस कर\r\nलीजिएगा एग्जांपल साथ में रहेंगे नहीं कुछ\r\nइशू होगा तो हम लोग डिस्कस कर लेंगे आपके\r\nक्लास के बाद चलिए\r\nफिर अगला पॉइंट आता है रेमेडीज\r\nक्या होती है बेसिकली देखिए पहले तो मुझे\r\nयह पता होना चाहिए की समस्या का कारण क्या\r\nहै तो उसके लिए कारण लग्न चार्ट में ढूंढो\r\nया डिविजनल चार्ट में मिलेगा या मुझे कारण\r\nगोचर में मिलेगा या अगला से संबंधित है\r\narundha पड़ा से संबंधित है घाटी लग्न\r\nसंबंधित है पहले तो मुझे ये जानना जरूरी\r\nहै फिर मैंने अपने जातक को एक मंत्र जाप\r\nदे दिया\r\nकी भाई मंत्र कर लेना और उसने वो मंत्र\r\nनहीं किया तो मैं बोलूंगा की ऐसे डॉक्टर\r\nमैंने मेडिसिन दे दी मेरा कम खत्म\r\nठीक है बात सही है लेकिन एस्ट्रोलॉजर ने\r\nयह प्रोफेशन तो है लेकिन साथ में एक जरिया\r\nहै लोगों की समस्या को सॉल्व करने का तो\r\nआपको यह देखना है की वह व्यक्ति आपका दिया\r\nहुआ रेमेडी करने में इंप्रेस्ड है या नहीं\r\nहै\r\nकैसे उससे पूछेंगे तो वह तो बोलेगा की हान\r\nजी आपके हाथ में उसका लगने चैट होगा जिससे\r\nदेख के आप देख बता सकते हैं की इस व्यक्ति\r\nका मंत्र उच्चारण करने में मैन लगेगा नहीं\r\nलगेगा ये रेगुलर कर पाएगा या नहीं कर\r\nपाएगा तो ऐसे एक अच्छे एस्ट्रोलॉजर नजरिया\r\nसे देखूं तो मैं रेमेडी भी बहुत सोच समझ\r\nके दूंगा क्योंकि समझिए मुझे क्या चाहिए\r\nआपको क्या चाहिए फाइनल की आप जो बोलो वो\r\nहो और आप जो उपाय दो वो सामने वाला करें\r\nऔर उसको रिजल्ट मिले यह सब हमारे\r\nरिस्पांसिबिलिटी है तो रेमेडी देते समय\r\nयाद रखना है की किस तरह की रेमेडी के\r\nसामने वाला पर्सन बहुत खुशी से करेगा और\r\nउसको अच्छे रिजल्ट मिलेंगे यह बहुत\r\nमहत्वपूर्ण हो जाता है\r\nआमतौर पर हम लोग भला दल देते हैं की हमने\r\nरेमेडी लिख दी अपने घर कर लेना ये पर्पस\r\nनहीं होता ज्योतिष का एस्ट्रोलॉजी बहुत\r\nबड़ा साइंस है जिसे बनाया गया है\r\nलोगों की लाइफ को बटर बनाने के लिए तो हम\r\nजितना indift जाएंगे उतना हम बैटरी रिजल्ट\r\nदे पाएंगे\r\nअच्छा कुछ लोगों के लग रहा है क्या इतना\r\nसब पढ़ना है हम लोगों को बहुत ज्यादा हो\r\nरहा है चीजें हमने तो उसमें से कई चीज भी\r\nनहीं है ऐसा कोई\r\nतो अगर आपको ऐसा लग रहा है की यह बहुत\r\nसारा है तो मैं आपको थोड़ी सी चीज स्पष्ट\r\nकर डन की ये जो मैंने आपको बताया ये लगभग\r\n60% है तो 40% तो मैंने अभी एक्सप्लेन ही\r\nकिया है इसके अंदर अंदर आपको बहुत अच्छी\r\nचीज है इंटरेस्टिंग चीज है मिलेगी ठीक है\r\nचलिए\r\nकी हम लोग से इंडिया में क्या करने वाले\r\nहैं\r\nचलिए अब जल्दी से एक और समझ लेते हैं फिर\r\nहम लोग कल्पना फैशन स्टार्ट करेंगे 12\r\nहाउसेस से देखिए हर कुंडली में आपको 12 घर\r\nमिलेंगे कंफर्म यही चीज 12 राशियां मिलेगी\r\nनो डाउट मिलेंगे और नौ ग्रह मिलेंगे कोई\r\nभी कुंडली ऐसी नहीं होगी जिसमें ये तीन\r\nचीज ना हो ठीक है अब आपके पास कुंडली आएगी\r\nतो सबसे पहले क्वेश्चन आएगा की क्या देखो\r\nइसको दिल्ली में तो आपको देखना है जो\r\nसमस्या है उससे संबंधित भाव कौन सा है\r\nहाउस कौन सा है क्यों क्योंकि हाउस है जो\r\nप्रोमाइजेज करते हैं किसी चीज का आपकी\r\nलाइफ में और आपकी जिंदगी से रिलेटेड हर\r\nचीज किसी ना किसी घर में होती है तो इसका\r\nमतलब आपको 12 के 12 हाउस पता होने चाहिए\r\nऔर वह क्या देते हैं यह पता होना चाहिए तो\r\nइसलिए पढ़ना है\r\nयानी की ओनर जैसे बोलते हैं या फिर उसे घर\r\nका प्लान है है तो किसी भी घर का जो\r\nरिजल्ट है वह कौन कैरी करेगा रिजल्ट करी\r\nकरेगा उसे घर का प्लानिंग तो हम देखेंगे\r\nप्लैनेट कौन है कैसा है उसका स्वभाव कैसा\r\nहै कहां है इसलिए हमें प्लैनेट की स्टडी\r\nकरनी पड़ेगी हमें प्लानर तो को अच्छी तरह\r\nसमझना पड़ेगा फिर अगला क्वेश्चन कैसा\r\nरिजल्ट आएगा\r\nराशियां आपको ये बताती है की जो आपको\r\nरिजल्ट मिलेगा उसका नेचर कैसा होगा अब ये\r\nपॉइंट समझिए बहुत इंपॉर्टेंट है और लोग\r\nनॉर्मली इसको इग्नोर करते हैं बहुत इग्नोर\r\nकरते हैं मैन लीजिए कोई घर कुंडली में\r\nआपको पंच चीजों की प्रॉमिस करता है तो\r\nउसका लॉर्ड की दशा अंतर्दशा चली और वो\r\nअच्छा है तो क्या वो आपको पांचो चीज देगा\r\nनहीं वह डिपेंड करेगा राशि पर की वह\r\nप्लैनेट कौन सी राशि में आपकी कुंडली में\r\nआपके डिविजनल चैट में कौन सी कुंडली में\r\nऔर गोचर में कौन से सॉरी राशि में है तो\r\nइन तीनों में जिस जिस राशि में वो होगा\r\nवहां के रिजल्ट वो आपको देगा तो सारी चीज\r\nएक साथ नहीं दे देगा कोई भी प्लानिंग आपको\r\nया बहुत डिटेल में समझेगी और अगर आपने\r\nराशियों पे कमांड अच्छी कर ली तो आप इतने\r\nसती प्रिडिक्शन कर पाएंगे आप ये बता\r\nपाएंगे की आपको इस ड्यूरेशन में इस चीज का\r\nफायदा होगा मतलब आपको मॉनेटरी फायदा होगा\r\nआपको मेंटल पीस फायदा होगा या आपके परिवार\r\nसे संबंधित किसी व्यक्ति को फायदा होगा\r\nइतना दीप में जाके आप उसको बता पाएंगे\r\nसब होगा कब जाहिर है हम जानते हैं सब कुछ\r\nदशा अंतर्दशा महत्वपूर्ण होती है और उसके\r\nसाथ में गोचर को मैच करते हैं क्योंकि\r\nटाइम ऑफ रिजल्ट की जब बात करते हैं तो वो\r\nहमेशा आता है की दशा कब होगी अंतर्दशा कब\r\nहोगी और साथ में गोचर का कांबिनेशन क्या\r\nहोगा तो इसलिए ये तीन चीज पढ़ना\r\nमहत्वपूर्ण हो जाता है तो सेशन को और लंबा\r\nनहीं करते जी हान आपकी क्वेरीज है बस एक\r\nदो मिनट और उसके बाद हम लोग स्टार्ट करते\r\nहैं आपकी गारी जो भी हो उसके लिए ठीक है\r\nतो कल तो 11:00 बजे हम लोग अब तक स्टार्ट\r\nकरते हैं सेशन सबसे पहले समझेंगे 12\r\nहाउसेस और उनके इफेक्ट आपस में जो\r\nकांबिनेशन है उसे पर भी थोड़ी नजर डालेंगे\r\nऔर डिटेल में स्टडी करेंगे तो अभी आपके"}];
